-- spain/pre-move
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'pre-move');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'pre-move');
delete from public.wc_modules where country = 'spain' and slug = 'pre-move';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'pre-move', 1, 'Pre-move UK actions', 'The six-to-twelve month run-up. Every UK-side decision is cheaper and cleaner while you are still UK tax resident — this module sequences them so nothing is left stranded on the wrong side of the residency line.', '90 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Your UK exit, in the right order', '<p>Almost every five-figure mistake we see traces back to sequencing: doing something after Spanish tax residency that should have been done before, or vice versa. The residency line — the day you become Spanish tax resident — reprices almost every asset decision you can make. Before the line, HMRC rules apply. After it, Spanish rules apply to your worldwide income and gains.</p>
<p>The master sequence for the 6–12 months before departure:</p>
<ol>
<li><strong>Month -12 to -9:</strong> decide the target tax year for the move. Spanish residency is triggered by 183+ days in a <em>calendar</em> year — a move in July or later usually keeps you non-resident in Spain for that year, giving you a clean transition window. A January move makes you Spanish-resident for the whole arrival year.</li>
<li><strong>Month -9 to -6:</strong> UK asset review — ISAs, GIAs, pensions, property (each covered below). Get valuations dated and documented now; you will need them for Spanish acquisition-value purposes later.</li>
<li><strong>Month -6 to -3:</strong> visa document assembly (Module 2), apostilles, sworn translations.</li>
<li><strong>Month -3 to 0:</strong> consulate application, P85 preparation, notify UK institutions.</li>
</ol>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — The July trick</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Arriving in Spain after 2 July means you cannot hit 183 days in that calendar year. Your Spanish tax residency then starts on 1 January of the following year — giving you a 5-6 month runway on Spanish soil while still UK tax resident, during which UK-side disposals (ISA sales, GIA rebalancing, even a property completion) stay under UK rules. This single sequencing decision is worth more than any other planning trick in this module.</div></div>' from m union all select id, 1, 'Form P85 — and what it does not do', '<p>Form P85 tells HMRC you are leaving the UK. File it online through your Government Gateway account around your departure date — it triggers any in-year tax refund (you usually have unused personal allowance for the part-year) and sets up the NT (no tax) code process if you will have UK employment income paid gross.</p>
<p>What P85 does <strong>not</strong> do — and where accountants who rarely handle expatriation get it wrong:</p>
<ul>
<li>It does <strong>not determine your UK tax residency</strong>. Only the Statutory Residence Test does that. You can file a P85 and still be UK tax resident under the SRT if you keep too many ties and days. Read our <a href="/uk-statutory-residence-test">SRT guide</a> and count honestly.</li>
<li>It does <strong>not replace a Self Assessment return</strong>. If you normally file SA — or you have UK rental income, gains, or split-year treatment to claim — you still file for the departure year, with the SA109 residence pages.</li>
<li>It is <strong>not a deadline-critical form</strong> in the way Modelo 149 is (Module 3). File within a few weeks of leaving; earlier filings can be rejected as premature.</li>
</ul>
<p>If you will let out your UK home, also file <strong>form NRL1</strong> (Non-resident Landlord Scheme) so your letting agent or tenant can pay rent gross instead of withholding 20% at source.</p>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — Split-year treatment is claimed, not automatic</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">In the year you leave, you want the UK tax year split into a UK part and an overseas part (RDR3 Cases 1, 3 or 8 for most movers). It is claimed on the SA109 pages of your Self Assessment — miss the claim and HMRC treats you as UK resident for the full year, taxing your post-move income too, and unpicking it later costs accountant hours.</div></div>' from m union all select id, 2, 'ISA wind-down: the wrapper dies at the border', '<p>Spain does not recognise the ISA wrapper. From your first day of Spanish tax residency, everything inside an ISA becomes ordinary taxable assets: dividends and interest are taxed as savings income (19%–30% in 2026), and disposals crystallise Spanish-taxable gains — computed against your <em>original acquisition cost</em>, not the value on arrival.</p>
<p>That last point is the trap. There is no automatic rebasing on entry. A fund bought at £20,000 in 2015, worth £60,000 when you move, carries its full £40,000 gain into the Spanish system. Sell it in year 2 of Spanish residency and Spain taxes the whole gain at up to 30% — a gain that would have been entirely tax-free had you sold inside the ISA while still UK resident.</p>
<p>The playbook move, therefore:</p>
<ol>
<li>List every ISA holding with purchase dates and costs.</li>
<li>While still UK tax resident, <strong>sell and immediately repurchase</strong> (inside or outside the wrapper — the point is to reset the acquisition date and cost to today). UK CGT does not apply inside an ISA, so the reset is free.</li>
<li>Keep the contract notes. They are your Spanish acquisition-cost evidence for the decades ahead.</li>
<li>Decide whether to keep the account open at all — many platforms (Vanguard UK, HL, AJ Bell) restrict or freeze accounts for non-UK residents. Ask your platform its non-resident policy <em>before</em> you move; switching platforms is much easier with a UK address.</li>
</ol>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — ISA reset, £60k holding</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Original cost £20,000 → value at move £60,000. No reset: sell in Spain year 2 at £62,000 → Spanish CGT on £42,000 ≈ €11,300. With pre-move reset: Spanish gain is only the £2,000 growth since the reset ≈ €540 tax. The 20-minute reset saved roughly £9,300.</div></div>' from m union all select id, 3, 'UK property: sell before, sell after, or keep and let', '<p>Three paths, three very different tax outcomes.</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Path</th><th class="px-3.5 py-2.5">UK side</th><th class="px-3.5 py-2.5">Spain side</th><th class="px-3.5 py-2.5">Best for</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Sell before the residency line</td><td class="px-3.5 py-2.5 text-ink/85">Private Residence Relief usually wipes the gain on your main home</td><td class="px-3.5 py-2.5 text-ink/85">Nothing — you were not yet Spanish resident</td><td class="px-3.5 py-2.5 text-ink/85">Almost everyone who intends to sell at all</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Sell after becoming Spanish resident</td><td class="px-3.5 py-2.5 text-ink/85">UK CGT on gains since April 2015 (NRCGT return within 60 days of completion)</td><td class="px-3.5 py-2.5 text-ink/85">Spanish CGT 19–30% on the full gain since original purchase, with only partial main-home relief if reinvested in a Spanish main home (and only if you are 65+, full exemption)</td><td class="px-3.5 py-2.5 text-ink/85">Rarely optimal — usually an accident of timing</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Keep and let</td><td class="px-3.5 py-2.5 text-ink/85">UK income tax on rent (NRL scheme, personal allowance still available to UK/EEA citizens), 60-day NRCGT on eventual sale</td><td class="px-3.5 py-2.5 text-ink/85">Rent also taxable in Spain with credit for UK tax; property enters your Modelo 720 and wealth-tax base</td><td class="px-3.5 py-2.5 text-ink/85">Those who want the income and accept the double filing</td></tr></tbody></table></div>
<p>The main-home sale is the single largest number in most moves. If a sale is likely within a couple of years, complete it — exchange <em>and</em> completion — while UK resident and before Spanish residency begins. The July trick above buys you the extra months this often needs.</p>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — The 65+ exemption is Spain-side only</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Spain fully exempts main-home gains for over-65s — but only for a home that was your Spanish habitual residence for 3+ years. Your UK house never qualifies. Do not let anyone tell you "you are over 65 so the sale is tax-free" — that rule cannot rescue a UK property sold after you became Spanish resident.</div></div>' from m union all select id, 4, 'Pensions: sequence the drawdown decisions', '<p>Full pension mechanics live in Module 6 (year-one tax) and our <a href="/qrops-vs-sipp-abroad">QROPS vs SIPP deep dive</a>, but three decisions belong in the pre-move window:</p>
<ul>
<li><strong>The 25% tax-free lump sum is a UK concept.</strong> Spain does not exempt it — once Spanish resident, a lump sum is taxed as pension income at general rates (19–47%). If taking the Pension Commencement Lump Sum is part of your plan, take it while UK tax resident. This is frequently a five-figure decision.</li>
<li><strong>Do not trigger the MPAA carelessly.</strong> Flexibly accessing a DC pension drops your annual allowance to £10,000. If you might still contribute (e.g. you keep UK employment income for a while), take only the PCLS and leave the rest untouched.</li>
<li><strong>Government vs private pensions split differently under the treaty.</strong> UK government-service pensions (civil service, forces, police, most NHS) stay taxable only in the UK under Article 18(2) of the UK–Spain DTA. State pension and private pensions become taxable in Spain. Map which of your pensions is which now — it changes your Spanish bracket arithmetic and whether Beckham helps you at all (Module 3).</li>
</ul>
<p>Also brief your providers: several UK platforms restrict drawdown instructions from non-UK addresses, and some will not open new drawdown arrangements for non-residents at all. Getting drawdown <em>structured</em> (not necessarily drawn) before you leave keeps every option open.</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — PCLS timing, £400k pot</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Take the 25% lump sum (£100,000) while UK resident: £0 tax. Take it 6 months later as a Spanish resident: taxed as general income — on top of other income it lands mostly in the 37–45% bands ≈ €38,000–€45,000 of avoidable Spanish tax. Same money, one calendar decision.</div></div>' from m union all select id, 5, 'The document pack: apostilles and sworn translations', '<p>Spanish authorities only accept UK public documents that are (a) apostilled by the FCDO Legalisation Office and (b) translated by an official sworn translator (<em>traductor jurado</em>) accredited by the Spanish Ministry of Foreign Affairs. Do both before you leave — it is slower and more expensive from Spain.</p>
<p>Standard pack for a typical household:</p>
<ul>
<li>Birth certificates (each family member) — apostille + sworn translation</li>
<li>Marriage certificate — apostille + sworn translation</li>
<li>ACRO police certificate (needed for the visa; must be under 90 days old at application) — apostille</li>
<li>Degree/professional certificates if you may work — apostille + sworn translation</li>
<li>Medical certificate in consulate wording (Module 2) — usually issued bilingual, check your consulate</li>
</ul>
<p>2026 costs and timing: FCDO apostille £30–£45 per document, 2–10 working days by post (same-day premium service exists in London). Sworn translations run €35–€60 per page through translators on the MAEC list. ACRO standard service £63, 10–12 working days.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Order two ACRO certificates</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The ACRO certificate must be under 90 days old when the consulate receives your application. If your appointment slips — and consulate appointments slip constantly — a stale certificate restarts the clock. A second certificate ordered a month later is £63 of cheap insurance.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'target-year', 'Pick the target arrival window (July+ preserves a non-resident first year)', 'Confirms your first Spanish tax year and the length of your UK-rules runway.', null from m union all select id, 1, 'p85', 'File P85 with HMRC (plus NRL1 if letting your UK home)', null, 'within ~4 weeks of departure' from m union all select id, 2, 'sa109', 'Diarise the departure-year Self Assessment with SA109 split-year claim', null, 'by 31 Jan following the tax year' from m union all select id, 3, 'isa-reset', 'Reset ISA/GIA acquisition costs by sale-and-repurchase while UK resident', 'Keep every contract note — they are your Spanish cost-basis evidence.', null from m union all select id, 4, 'platform-policy', 'Confirm each investment platform''s non-resident policy in writing', null, null from m union all select id, 5, 'property-decision', 'Decide the UK property path (sell-before / sell-after / keep-and-let)', 'If selling: completion must land before the Spanish residency line.', null from m union all select id, 6, 'pcls', 'Decide on the 25% pension lump sum while still UK resident', 'Spain taxes it as income; the UK does not. One-way door.', null from m union all select id, 7, 'pension-map', 'Map each pension: government-service vs private vs state', 'Article 18 UK-Spain DTA treats them differently.', null from m union all select id, 8, 'documents', 'Apostille + sworn-translate the document pack; order ACRO (x2)', null, 'ACRO must be <90 days old at visa application' from m union all select id, 9, 'valuations', 'Date-stamp valuations of every significant asset at the move', 'Needed for Modelo 720 and future Spanish CGT calculations.', null from m;

-- spain/visa
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'visa');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'visa');
delete from public.wc_modules where country = 'spain' and slug = 'visa';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'visa', 2, 'Choosing the right visa', 'NLV, DNV, work permit or family reunification — with the 2026 thresholds, the document checklists consulates actually enforce, and the quirks of each UK consulate.', '120 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The decision tree', '<p>Post-Brexit, four routes cover essentially every British applicant. Start from your income type — it decides the route more than anything else:</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Your situation</th><th class="px-3.5 py-2.5">Route</th><th class="px-3.5 py-2.5">2026 income bar</th><th class="px-3.5 py-2.5">Work allowed?</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Passive income only (pension, rent, dividends)</td><td class="px-3.5 py-2.5 text-ink/85">Non-Lucrative Visa (NLV)</td><td class="px-3.5 py-2.5 text-ink/85">€28,800/yr + €7,200 per dependant (400% + 100% IPREM)</td><td class="px-3.5 py-2.5 text-ink/85">No — none, not even remote</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Remote employee or freelancer, non-Spanish clients</td><td class="px-3.5 py-2.5 text-ink/85">Digital Nomad Visa (DNV)</td><td class="px-3.5 py-2.5 text-ink/85">€2,849/mo gross (200% SMI); +75%/+25% SMI for dependants</td><td class="px-3.5 py-2.5 text-ink/85">Yes — remote for non-Spanish firms; ≤20% Spanish clients if freelance</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Job offer from a Spanish employer</td><td class="px-3.5 py-2.5 text-ink/85">Work visa (cuenta ajena)</td><td class="px-3.5 py-2.5 text-ink/85">Set by contract</td><td class="px-3.5 py-2.5 text-ink/85">Yes — for that employer</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Spouse/parent of an EU citizen or Spanish resident</td><td class="px-3.5 py-2.5 text-ink/85">Family reunification / EU family member</td><td class="px-3.5 py-2.5 text-ink/85">Sponsor shows means</td><td class="px-3.5 py-2.5 text-ink/85">Yes (EU-family route)</td></tr></tbody></table></div>
<p>Two routes people ask about that are usually wrong: the <strong>Golden Visa</strong> property route closed in 2025 (only fund/business investment variants survive, and they suit almost nobody reading this), and <strong>student visas</strong> — real, but a poor fit for permanent movers because years on a student card count only 50% toward long-term residency.</p>
<p>The NLV-vs-DNV boundary is the one that matters. The NLV bans <em>all</em> work — including UK remote work. Consulates now actively look for employment income in your bank statements and will refuse or later non-renew if they find it. If you will keep working remotely, the DNV is not optional — it is the only honest route, and it happens to come with Beckham Law eligibility (Module 3), which the NLV does not.</p>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — The NLV remote-work myth</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Forums are full of "just get the NLV and keep your UK job quiet." Consulates cross-read your own submitted bank statements; salary credits are visible. Refusals on this ground are rising, and a refusal goes on your record for every future Schengen application. If you work, apply DNV.</div></div>' from m union all select id, 1, 'NLV: proving passive income properly', '<p>The 2026 NLV bar is 400% of IPREM for the main applicant — <strong>€28,800/year (€2,400/month)</strong> — plus 100% of IPREM (<strong>€7,200/year</strong>) per dependant. A couple therefore shows €36,000; a family of four €50,400. IPREM is frozen at €600/month for 2026; it moves most years, so re-check in the year you apply (<a href="/thresholds">live table here</a>).</p>
<p>What counts, in descending order of how much consulates like it:</p>
<ol>
<li><strong>Pensions in payment</strong> — state, occupational, annuities. Show award letters + 6 months of bank credits.</li>
<li><strong>Rental income</strong> — tenancy agreements + 6–12 months of credits + latest SA return.</li>
<li><strong>Dividends/interest from a portfolio</strong> — broker statements + tax returns. Some consulates also want to see the capital base.</li>
<li><strong>Savings alone</strong> — accepted case-by-case, typically at 4× the annual requirement (~€115,000+ for a single applicant) and never guaranteed. Pair savings with at least some recurring income if you can.</li>
</ol>
<p>Everything financial must be officially translated, and consulates want consistency: the same numbers appearing in bank statements, tax returns and award letters. Round-number "top-up" transfers from relatives the month before applying are spotted instantly and read as gaming.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Show net, organised, boring</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Consulate reviewers spend minutes, not hours, per file. A single PDF per income source — award letter, then statements highlighted where the credit lands, then translation — gets approved. Sixty loose pages of raw statements gets "additional documentation requested" and a 2-month delay.</div></div>' from m union all select id, 2, 'DNV: the remote-worker file', '<p>The DNV bar for 2026 is 200% of the SMI — <strong>€2,849/month gross</strong> for the main applicant, +75% SMI (~€1,068) for the first dependant, +25% (~€356) for each further dependant. The SMI rises most years; verify at application time.</p>
<p>Beyond income, the DNV file has four load-bearing documents:</p>
<ul>
<li><strong>Employer letter (employees)</strong>: confirms your role, salary, that remote work from Spain is authorised, and that the company has operated for 1+ year. On company letterhead, signed, translated.</li>
<li><strong>Company registration proof</strong>: Companies House extract for a UK employer, apostilled.</li>
<li><strong>Social security coordination</strong>: either an A1 certificate from HMRC keeping you in UK NI (rare post-Brexit; the UK-Spain bilateral makes this possible for postings but most applicants instead register as autónomo in Spain), or a signed commitment to register with Spanish social security. Freelancers: you will become <a href="/spain/autonomo">autónomo</a> after arrival — the consulate wants to see you know that.</li>
<li><strong>Qualifications or experience</strong>: degree certificate (apostilled) or evidence of 3+ years professional experience in your field.</li>
</ul>
<p>Freelancers may bill Spanish clients up to 20% of turnover — but the cleaner your file reads as "foreign clients only," the smoother the approval. You can apply at the UK consulate (3-year card via UGE route in some cases, commonly 1-year visa then 3-year renewal) or enter Spain and apply in-country to the UGE within your 90 visa-free days — the in-country route gets you a 3-year card immediately and is now the more popular path.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — In-country UGE application</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Fly to Spain as a tourist, apply online to the Unidad de Grandes Empresas within your first weeks, receive a 3-year residence card, skip the consulate queue entirely. Processing is a statutory 20 working days with positive administrative silence. This is how most 2026 DNV approvals are actually happening — but do not start work in Spain before the approval lands.</div></div>' from m union all select id, 3, 'The medical certificate and criminal record, decoded', '<p>Two documents cause a disproportionate share of rejections:</p>
<p><strong>Medical certificate.</strong> Must state — in wording that tracks the International Health Regulations 2005 — that you do not suffer from diseases with serious public-health repercussions. UK GPs often refuse or write their own wording; consulates then reject it. Use a private GP service that knows the Spanish consular formula (£80–£150), request it bilingual or have it sworn-translated, and date it inside 90 days of your appointment.</p>
<p><strong>ACRO police certificate.</strong> Covers the last 5 years of residence. "Stepped down" convictions still appear in some data sets — if you have any record at all, take advice before applying rather than hoping. Apostille required. Under 90 days old at submission (some consulates say 6 months — the safe play is 90 days).</p>
<p>Both documents are per-adult; children under 18 need neither (medical requirements for minors vary by consulate — check yours).</p>' from m union all select id, 4, 'Consulate quirks: London, Manchester, Edinburgh', '<p>Your consulate is fixed by where you live (jurisdiction is enforced — a Manchester-area resident cannot file in London). As of early 2026:</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Consulate</th><th class="px-3.5 py-2.5">Covers</th><th class="px-3.5 py-2.5">Booking reality</th><th class="px-3.5 py-2.5">Notes</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">London</td><td class="px-3.5 py-2.5 text-ink/85">South England, Wales</td><td class="px-3.5 py-2.5 text-ink/85">BLS-operated appointments; released in blocks, gone in minutes; 4–10 week wait typical</td><td class="px-3.5 py-2.5 text-ink/85">Strictest on document formatting; wants the medical certificate in its own bilingual template</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Manchester</td><td class="px-3.5 py-2.5 text-ink/85">Midlands + North England</td><td class="px-3.5 py-2.5 text-ink/85">2–6 week waits; steadier release</td><td class="px-3.5 py-2.5 text-ink/85">Most pragmatic of the three on savings-based NLV files</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Edinburgh</td><td class="px-3.5 py-2.5 text-ink/85">Scotland, NI, far North</td><td class="px-3.5 py-2.5 text-ink/85">Shortest queues, small team</td><td class="px-3.5 py-2.5 text-ink/85">Slower decisions in summer; phone contact actually works</td></tr></tbody></table></div>
<p>Decision times once submitted: NLV is nominally 1 month, really 4–10 weeks. Consulate DNV: similar. In-country UGE DNV: 20 working days statutory. You surrender your passport to the visa sticker process only at the end — but plan no travel in the last 2–3 weeks before collection.</p>
<div class="rounded-card border border-warning/50 bg-warning/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⏰ Deadline — Visa → entry → TIE chain</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The visa in your passport is valid 90 days. You must enter Spain within it, and then apply for your TIE card within 30 days of arrival (Module 4). Book the TIE fingerprint appointment (cita previa) the week you land — in Málaga, Alicante and Barcelona provinces, appointments run 3-6 weeks out.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'route', 'Lock the route: NLV (no work at all) vs DNV (remote work) vs other', 'If any employment income will continue, it must be DNV.', null from m union all select id, 1, 'income-evidence', 'Assemble income evidence to the 2026 bar (€28,800 NLV / €2,849-mo DNV + dependant uplifts)', 'One organised PDF per income source.', null from m union all select id, 2, 'acro', 'Order ACRO certificate(s) and apostille', null, '<90 days old at submission' from m union all select id, 3, 'medical', 'Book consulate-wording medical certificate (bilingual)', null, '<90 days old at submission' from m union all select id, 4, 'apostille-translate', 'Apostille + sworn-translate every UK document in the file', null, null from m union all select id, 5, 'insurance', 'Buy visa-compliant Spanish health policy — zero copay, no caps (Module 7)', 'Sanitas / Adeslas / DKV issue consulate-format certificates.', null from m union all select id, 6, 'appointment', 'Book consulate appointment (or plan the in-country UGE route for DNV)', null, null from m union all select id, 7, 'submit', 'Submit, track, and calendar the 90-day entry window on approval', null, null from m union all select id, 8, 'tie-plan', 'Pre-book the TIE cita previa for the week after landing', null, 'TIE application within 30 days of entry' from m;

-- spain/beckham-law
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'beckham-law');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'beckham-law');
delete from public.wc_modules where country = 'spain' and slug = 'beckham-law';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'beckham-law', 3, 'Beckham Law structuring', 'The special impatriate regime: 24% flat on Spanish employment income up to €600,000, foreign investment income outside Spanish tax entirely — for six years. Who qualifies, when standard IRPF actually wins, and the six-month election that cannot be recovered if missed.', '90 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'What the regime actually does', '<p>Article 93 LIRPF — the "Beckham Law" — lets qualifying new arrivals elect to be taxed like non-residents for the year of arrival plus the five following years. In practice, for a British mover, three effects matter:</p>
<ul>
<li><strong>Employment income at 24% flat</strong> up to €600,000/year (47% above). Compare standard IRPF where 24% is passed at roughly €35,000 of income and the top marginal rates run 45–50% depending on region.</li>
<li><strong>Foreign-source investment income is outside Spanish tax.</strong> UK dividends, interest, and capital gains on non-Spanish assets are simply not taxed by Spain while you are in the regime. (UK withholding/UK rules may still apply — e.g. UK rental income stays UK-taxable.)</li>
<li><strong>No Modelo 720, and wealth tax only on Spanish-situs assets.</strong> The foreign-asset declaration does not apply to Beckham participants, and Patrimonio/Solidaridad reach only your Spanish assets — a large quiet benefit for anyone with UK property or portfolios.</li>
</ul>
<p>Who qualifies (2026 rules, post-2023 expansion): you must not have been Spanish tax resident in the <strong>5 years</strong> before the move, and your move must be caused by one of — a Spanish employment contract; <strong>remote work for a foreign employer (the DNV case, explicitly added in 2023)</strong>; appointment as a director; qualifying entrepreneurial activity; or being a highly-qualified professional serving startups. Your accompanying spouse and children under 25 can also opt in under linked rules.</p>
<p>Who does <em>not</em>: autónomos with ordinary freelance activity (unless within the entrepreneur/highly-qualified carve-outs — specialist advice needed), professional sportspeople (excluded since 2015, ironically), and anyone whose income would flow through a Spanish permanent establishment.</p>' from m union all select id, 1, 'The six-month window — the least forgiving deadline in this playbook', '<div class="rounded-card border border-warning/50 bg-warning/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⏰ Deadline — Modelo 149, six months, no extensions, no second chances</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The election is filed on Modelo 149 within six months of the start date of your Spanish social security registration (or the posting certificate). Day one of that clock is not your arrival date — it is the alta date in the social security system. Miss it by a day and the regime is gone for your entire stay in Spain. There is no discretionary relief. Diarise it three ways the week you register.</div></div>
<p>Mechanics: file Modelo 149 electronically with your digital certificate or through your asesor. AEAT responds with a certificate of inclusion, usually inside 10 working days. From then on your employer withholds at the flat 24% (they need the certificate to run payroll correctly — give it to them immediately), and each spring you file <strong>Modelo 151</strong> (not the ordinary Modelo 100) as your annual return.</p>
<p>Duration and exit: arrival year + 5. You can renounce early (during November–December for the following year) — occasionally worth it if your income mix changes, e.g. you stop work and start living off foreign dividends that standard IRPF would tax at 19–30% but that also stop being your main income. Run the numbers before renouncing; you cannot re-enter.</p>' from m union all select id, 2, 'Beckham vs standard IRPF: who wins where', '<p>Beckham is not automatically better. It trades a flat 24% and foreign-income exemption for the loss of personal/family allowances, the loss of most deductions, and — crucially — <em>no access to double-tax-treaty relief as a Spanish resident</em> (you are taxed as a non-resident, so some UK-source items like pensions can end up worse). The pattern:</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Profile</th><th class="px-3.5 py-2.5">Better regime</th><th class="px-3.5 py-2.5">Why</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Salary €60k, little else</td><td class="px-3.5 py-2.5 text-ink/85">Beckham — narrowly</td><td class="px-3.5 py-2.5 text-ink/85">Standard IRPF effective rate ≈ 27–29% vs flat 24%; gap widens fast above this</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Salary €120k+</td><td class="px-3.5 py-2.5 text-ink/85">Beckham — decisively</td><td class="px-3.5 py-2.5 text-ink/85">Standard marginal 45%+ vs 24%; five-figure annual saving</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Salary €45k + large UK dividend portfolio</td><td class="px-3.5 py-2.5 text-ink/85">Beckham</td><td class="px-3.5 py-2.5 text-ink/85">The exemption on foreign investment income usually outweighs everything else</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Salary under ~€50k, spouse + kids, mortgage</td><td class="px-3.5 py-2.5 text-ink/85">Often standard IRPF</td><td class="px-3.5 py-2.5 text-ink/85">Allowances (mínimo familiar), joint filing and deductions can beat the flat rate below ~€50-55k</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Retiree, UK pensions only</td><td class="px-3.5 py-2.5 text-ink/85">Beckham unavailable/pointless</td><td class="px-3.5 py-2.5 text-ink/85">Pension income is not employment income for these purposes; regime needs a qualifying work move</td></tr></tbody></table></div>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — Worked example — £95,000 remote salary (≈ €111,000)</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Standard IRPF (Andalucía, single, no kids): ≈ €38,900 tax, effective 35%. Beckham: €111,000 × 24% = €26,640, effective 24%. Saving ≈ €12,260/yr, ≈ €73,500 over the six years — before counting the foreign-dividend exemption or the Modelo 720/wealth-tax relief. At £50k salary the same comparison shrinks to roughly €1,500–2,500/yr and can invert with family allowances.</div></div>
<p>Run your own numbers with the <a href="/calculators/beckham-law">Beckham calculator</a> (also embedded below), then sanity-check the edge cases with an asesor who files Modelo 151s routinely — many high-street gestorías never see one.</p>' from m union all select id, 3, 'Traps that cost real money', '<ul>
<li><strong>UK pensions under Beckham:</strong> as a treaty non-resident you can lose the DTA article that keeps private-pension taxation exclusive to residence. If a large pension drawdown is imminent, model it — Beckham can make pension income <em>worse</em>.</li>
<li><strong>Spanish-source investment income</strong> (Spanish dividends, Spanish rental) is still taxed under the regime, at non-resident rates. Beckham does not shelter your Marbella buy-to-let.</li>
<li><strong>Employer compliance:</strong> if your foreign employer refuses/fails to register the Spanish payroll or social-security position properly, your Modelo 149 clock and eligibility get murky. DNV holders working for a UK employer commonly resolve this via autónomo-style registration or an Employer of Record — decide the mechanism before you land, not after.</li>
<li><strong>The 5-year lookback is strict:</strong> even a forgotten year of Spanish tax residency in the past 5 (a sabbatical year, a pandemic year that hit 183 days) kills eligibility.</li>
<li><strong>Exit planning:</strong> in year 7 you fall onto standard IRPF with worldwide taxation, Modelo 720, and wealth tax. If your plan is a 5–6 year Spanish chapter, calendar the exit against this cliff; if permanent, use the Beckham years to restructure (e.g. realise foreign gains tax-free before year 7).</li>
</ul>' from m union all select id, 4, 'Run your numbers', '<p>Use the live calculator below with your actual salary. It compares standard IRPF against the Beckham flat rate for your income level — the crossover typically sits around €50,000–€55,000 for a single filer, higher with family allowances.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'lookback', 'Verify 5-year non-residency lookback — check every year honestly', 'Any 183+ day Spanish year in the window kills eligibility.', null from m union all select id, 1, 'trigger', 'Confirm your qualifying trigger (contract / DNV remote work / director / entrepreneur)', null, null from m union all select id, 2, 'payroll-mechanism', 'Agree the payroll & social security mechanism with your employer (or EoR/autónomo route) before arrival', null, null from m union all select id, 3, 'model', 'Model Beckham vs standard IRPF on your full income mix', 'Include foreign dividends, pensions, and the Modelo 720/wealth-tax effect — not just salary.', null from m union all select id, 4, 'alta-date', 'Record your social security alta date the day it happens', 'This starts the 6-month Modelo 149 clock.', null from m union all select id, 5, 'form-149', 'File Modelo 149', null, 'within 6 months of the alta — absolute' from m union all select id, 6, 'certificate', 'Deliver the AEAT inclusion certificate to your employer for 24% withholding', null, null from m union all select id, 7, 'modelo-151', 'Diarise Modelo 151 (not 100) for each spring of the regime', null, null from m union all select id, 8, 'family', 'File linked elections for spouse/children if beneficial', null, null from m union all select id, 9, 'exit-plan', 'Calendar the year-7 cliff: restructure foreign gains before the regime ends', null, null from m;

-- spain/arriving
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'arriving');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'arriving');
delete from public.wc_modules where country = 'spain' and slug = 'arriving';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'arriving', 4, 'Arriving and registering', 'NIE, TIE, padrón, Modelo 030, social security — five registrations, one correct order, and the regional quirks that change the paperwork in Andalucía, Madrid, Valencia and Cataluña.', '75 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The order of operations', '<p>Everything in Spanish bureaucracy hangs off something else. Do these in sequence and each step takes days; do them out of order and you will be collecting rejections:</p>
<ol>
<li><strong>NIE</strong> — your foreigner identification number. If you came through a consulate visa, an NIE is usually assigned inside the visa itself (check the sticker). Otherwise apply with form EX-15 + Modelo 790-012 fee (~€10) at a policía nacional extranjería office.</li>
<li><strong>Empadronamiento (padrón)</strong> — registration at your town hall as living at your address. Bring passport, rental contract (or landlord authorisation), and the completed form. Free. The certificate (volante) it produces is the key that opens healthcare, schools, TIE and residency-day evidence.</li>
<li><strong>TIE fingerprint appointment</strong> — within 30 days of entry for visa holders. Form EX-17, Modelo 790-012 fee (~€16-22), passport, visa, padrón, photo. Card ready for collection in 3–5 weeks.</li>
<li><strong>Modelo 030</strong> — registers/updates your address with the tax agency (AEAT). Ten minutes online with a digital certificate, or in person. Without it, AEAT notifications go nowhere — and AEAT notifications carry deadlines.</li>
<li><strong>Social security (alta)</strong> — via your employer, or yourself if autónomo (Module 6 covers the autónomo path). Remember: this alta date starts the Beckham 6-month clock.</li>
</ol>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Get a digital certificate immediately</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The certificado digital (FNMT) or Cl@ve registration turns every subsequent interaction — AEAT, social security, DGT, town halls — from a queue into a web form. Request it as soon as you have your NIE; validation is one short in-person appointment, and it will save you literal days across year one.</div></div>' from m union all select id, 1, 'The padrón, properly', '<p>The padrón is deceptively important. It is the document Spain treats as ground truth for where you live: healthcare card issuance keys off it, school places are allocated by padrón catchment, the Convenio Especial healthcare buy-in requires 12 continuous months of it, and at renewal time it evidences your residence continuity.</p>
<p>Practicalities that differ by town hall:</p>
<ul>
<li>Most big-city ayuntamientos need a <em>cita previa</em> booked online; smaller towns take walk-ins.</li>
<li>Renting a room or staying with friends? The property owner can register you with a signed authorisation + their ID — you do not need your own lease.</li>
<li>Some ayuntamientos (Madrid, Barcelona) now do periodic re-confirmation letters for non-EU registrants — respond to them or you get silently removed, which breaks the continuity you may later need.</li>
</ul>
<p>Every family member gets registered, including children — schools will ask for each child''s own volante de empadronamiento.</p>' from m union all select id, 2, 'Regional quirks worth knowing', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Region</th><th class="px-3.5 py-2.5">What is different</th><th class="px-3.5 py-2.5">Practical effect</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Andalucía</td><td class="px-3.5 py-2.5 text-ink/85">Extranjería offices in Málaga are the busiest in Spain; TIE citas scarce</td><td class="px-3.5 py-2.5 text-ink/85">Book the TIE appointment before you fly; consider quieter provincial offices (e.g. Antequera vs Málaga capital) where jurisdiction allows</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Madrid</td><td class="px-3.5 py-2.5 text-ink/85">Everything digitalised; padrón re-confirmations enforced</td><td class="px-3.5 py-2.5 text-ink/85">Fastest region end-to-end if you have the digital certificate; do not ignore padrón letters</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Valencia/Alicante</td><td class="px-3.5 py-2.5 text-ink/85">Huge expat volume; sworn-translation demands stricter at some town halls</td><td class="px-3.5 py-2.5 text-ink/85">Carry translations of the rental contract if it is in English</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Cataluña</td><td class="px-3.5 py-2.5 text-ink/85">Some municipal forms Catalan-first; NIE/TIE queues in Barcelona long</td><td class="px-3.5 py-2.5 text-ink/85">Allow +2-4 weeks vs elsewhere; small towns around Barcelona are faster than the city</td></tr></tbody></table></div>
<p>None of these change the law — they change the waiting time and the photocopies. The playbook rule: <strong>book every appointment the moment the previous document is in hand</strong>, because the queue is always the bottleneck.</p>' from m union all select id, 3, 'Driving licence: the 6-month window', '<p>Your UK licence is valid for driving in Spain for your first 6 months of residency. Under the UK–Spain agreement in force since 2023, you can <strong>exchange</strong> it for a Spanish licence without retesting — but the exchange must be initiated within that window (the DGT counts from your TIE issue date in practice).</p>
<p>Process: DGT cita previa → psychophysical aptitude test at an authorised centre (~€40–€60, eyesight/reflex check) → exchange application (~€28 fee) → temporary permit while the card arrives. After 6 months without initiating, you are legally an unlicensed driver in Spain and would need to sit the full Spanish test — in Spanish, theory and practical. Do not let this one drift.</p>
<div class="rounded-card border border-warning/50 bg-warning/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⏰ Deadline — Initiate the DGT exchange within 6 months of residency</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The queue for DGT appointments in coastal provinces regularly runs 4-8 weeks — meaning the real deadline to start looking is month 4, not month 6.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'nie', 'Confirm/obtain NIE (check your visa sticker first)', 'EX-15 + Modelo 790-012 if not already assigned.', null from m union all select id, 1, 'padron', 'Register the whole family on the padrón', 'Get a volante for each person; schools and healthcare will ask.', null from m union all select id, 2, 'tie', 'TIE fingerprint appointment (EX-17)', null, 'apply within 30 days of entry' from m union all select id, 3, 'digital-cert', 'Obtain FNMT digital certificate / Cl@ve for the whole household', null, null from m union all select id, 4, 'modelo-030', 'File Modelo 030 registering your Spanish tax address', null, null from m union all select id, 5, 'ss-alta', 'Complete social security alta (employer or autónomo)', 'Record the date — Beckham clock starts here.', null from m union all select id, 6, 'licence', 'Initiate UK→Spanish driving licence exchange at the DGT', null, 'start by month 4 of residency' from m union all select id, 7, 'collect-tie', 'Collect the TIE card and photograph/back up every document', null, null from m;

-- spain/banking
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'banking');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'banking');
delete from public.wc_modules where country = 'spain' and slug = 'banking';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'banking', 5, 'Spanish banking', 'The two-account architecture: a Spanish bank for Bizum, direct debits and landlord credibility; Wise or Revolut for moving money at real exchange rates. Plus what each bank actually demands from a new arrival in 2026.', '60 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The two-account architecture', '<p>Do not try to live in Spain from a UK account plus a card, and do not move your life savings into a Spanish account either. The setup that works:</p>
<ul>
<li><strong>A Spanish current account</strong> — because Spanish life runs on it: rent (landlords expect a Spanish IBAN and often a domiciliación), utilities and phone direct debits, Bizum (the ubiquitous P2P payment app — see below), and salary if employed locally.</li>
<li><strong>Wise (or Revolut) as the FX bridge</strong> — GBP→EUR at mid-market ±0.4–0.6% instead of the 2–3% buried spread in a bank international transfer. Fund the Spanish account from Wise in EUR via SEPA (arrives in hours, free/cheap).</li>
<li><strong>Your UK account stays open</strong> — for UK income, UK direct debits you keep (subscriptions, insurance), and credit-history continuity. Tell the bank you have moved (address change to Spain) rather than letting them find out; policies on non-resident customers vary and being upfront prevents sudden freezes.</li>
</ul>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — The FX bleed, quantified</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Moving £4,000/month via a UK bank''s international transfer at a typical 2.4% all-in spread costs ≈ £96/month. Via Wise at ~0.45%: ≈ £18. Same money, £930+/year difference — forever. This is the highest-ROI 20 minutes in this module.</div></div>' from m union all select id, 1, 'Which Spanish bank, for whom', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Bank</th><th class="px-3.5 py-2.5">Account to ask for</th><th class="px-3.5 py-2.5">Fees (2026)</th><th class="px-3.5 py-2.5">Best for</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Sabadell</td><td class="px-3.5 py-2.5 text-ink/85">Cuenta Expansión (expat desk)</td><td class="px-3.5 py-2.5 text-ink/85">€0 with conditions; English-speaking branches on the costas</td><td class="px-3.5 py-2.5 text-ink/85">Coastal movers who want an English-speaking branch human</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">BBVA</td><td class="px-3.5 py-2.5 text-ink/85">Cuenta Online Sin Comisiones</td><td class="px-3.5 py-2.5 text-ink/85">€0 online, no conditions</td><td class="px-3.5 py-2.5 text-ink/85">Best app in Spanish banking; fine fully-remote once you have NIE</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Santander</td><td class="px-3.5 py-2.5 text-ink/85">Cuenta Online / One</td><td class="px-3.5 py-2.5 text-ink/85">€0 online tier</td><td class="px-3.5 py-2.5 text-ink/85">Biggest branch network; useful for cash-heavy needs</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">CaixaBank</td><td class="px-3.5 py-2.5 text-ink/85">Day-to-day + imaginBank</td><td class="px-3.5 py-2.5 text-ink/85">€0 (imagin) / conditions otherwise</td><td class="px-3.5 py-2.5 text-ink/85">Dense ATM coverage; HolaBank desks for foreigners in tourist areas</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Openbank</td><td class="px-3.5 py-2.5 text-ink/85">Cuenta Corriente</td><td class="px-3.5 py-2.5 text-ink/85">€0, no conditions</td><td class="px-3.5 py-2.5 text-ink/85">Santander-owned digital; easy second account</td></tr></tbody></table></div>
<p><strong>What they ask a new arrival for:</strong> passport + NIE (or TIE), proof of address (padrón or rental contract), and — under anti-money-laundering rules — proof of economic activity: an employment contract, pension letters, or last UK tax return. Non-resident accounts (pre-NIE) exist at most banks with a <em>certificado de no residencia</em> but carry fees; open the resident account once your NIE exists and the fees drop to zero.</p>
<p><strong>Bizum</strong>: activate it inside your Spanish bank''s app the day the account opens. It is how Spaniards split dinner, pay the cleaner, pay the plumber''s deposit, buy second-hand. Wise/Revolut cannot join it — this alone justifies the Spanish account.</p>' from m union all select id, 2, 'Direct debits, deposits and the paperwork month', '<p>Month one banking admin, in order:</p>
<ol>
<li>Open the Spanish account (bring the full document stack; one visit if prepared).</li>
<li>Activate Bizum + the debit card + app.</li>
<li>Give the IBAN to your landlord; set the rent domiciliación if asked.</li>
<li>Move utilities (electricity, water, gas, internet, phone) onto Spanish direct debit — utility companies bill fortnightly-to-monthly and failed debits get services cut fast in Spain.</li>
<li>Audit your UK direct debits: kill the dead ones (gym, TV licence, UK breakdown cover), keep the UK-relevant ones on the UK account.</li>
<li>Set a monthly Wise standing transfer (salary day + 1) so the Spanish account never runs dry — failed Spanish direct debits incur €20–€39 fees <em>per bounce</em> at most banks.</li>
</ol>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — Deposit protection is per-bank, per-country</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Spanish accounts are protected by the Spanish FGD to €100,000 per person per bank — separate from (not additive with) your UK FSCS £85,000. Keep working balances in Spain and larger reserves where you have deliberate protection, not by accident of where a transfer landed.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'wise', 'Open Wise (and/or Revolut) before leaving the UK', 'Verification is easier with a UK address.', null from m union all select id, 1, 'main', 'Open the Spanish resident account once NIE is in hand', null, null from m union all select id, 2, 'bizum', 'Activate Bizum + card + app on day one', null, null from m union all select id, 3, 'rent', 'Give landlord the Spanish IBAN; set rent payment method', null, null from m union all select id, 4, 'utilities', 'Move all Spanish utilities to Spanish direct debit', null, null from m union all select id, 5, 'standing-transfer', 'Set a monthly Wise GBP→EUR standing transfer', 'Never fund Spanish debits ad hoc — bounces cost €20-39 each.', null from m union all select id, 6, 'uk-audit', 'Audit UK direct debits: cancel dead ones, keep deliberate ones', null, null from m union all select id, 7, 'notify-uk-bank', 'Notify UK bank of your Spanish address', null, null from m;

-- spain/year-one-tax
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'year-one-tax');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'year-one-tax');
delete from public.wc_modules where country = 'spain' and slug = 'year-one-tax';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'year-one-tax', 6, 'Year-one tax filing', 'Modelo 100 (or 151), Modelo 720, autónomo quarterlies, wealth tax — the full year-one filing calendar with worked examples for the standard UK income mix: salary, pensions, UK rent, dividends.', '120 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Your first Spanish tax year, mapped', '<p>Spain taxes the calendar year. You are tax resident for a year if you spend 183+ days in Spain in it (or your centre of economic interests is here). The first year you cross that line, your <em>entire</em> worldwide income for that calendar year comes into Spanish scope — including months before you physically arrived. This is why Module 1''s July trick matters so much.</p>
<p>The filing calendar you now live on:</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">When</th><th class="px-3.5 py-2.5">What</th><th class="px-3.5 py-2.5">Who</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">11 Apr – 30 Jun</td><td class="px-3.5 py-2.5 text-ink/85">Modelo 100 (IRPF annual return) — or Modelo 151 for Beckham participants</td><td class="px-3.5 py-2.5 text-ink/85">Everyone resident the prior calendar year</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">1 Jan – 31 Mar</td><td class="px-3.5 py-2.5 text-ink/85">Modelo 720 — foreign assets declaration</td><td class="px-3.5 py-2.5 text-ink/85">Residents with foreign assets >€50k in any category (not Beckham)</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">By 30 Jun</td><td class="px-3.5 py-2.5 text-ink/85">Modelo 714 — wealth tax, where due</td><td class="px-3.5 py-2.5 text-ink/85">Depends on region + net wealth (see below)</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">20 Apr / Jul / Oct / 30 Jan</td><td class="px-3.5 py-2.5 text-ink/85">Modelos 130 + 303 quarterlies</td><td class="px-3.5 py-2.5 text-ink/85">Autónomos</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">30 Jun (typically)</td><td class="px-3.5 py-2.5 text-ink/85">Solidaridad (Modelo 718) if net wealth > €3m</td><td class="px-3.5 py-2.5 text-ink/85">HNW residents</td></tr></tbody></table></div>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Year-one professional help is not optional</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">File year one with a cross-border asesor (€300–€600 for a standard return, €600–€1,200 with 720 and UK income). From year two, simple situations can self-file through Renta Web — it pre-populates Spanish-source data. What it never pre-populates is your UK income, which is exactly the part that gets people fined.</div></div>' from m union all select id, 1, 'How your UK income lands in the Spanish return', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">UK income</th><th class="px-3.5 py-2.5">Spanish treatment</th><th class="px-3.5 py-2.5">UK treatment after treaty</th><th class="px-3.5 py-2.5">Mechanics</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">UK state pension</td><td class="px-3.5 py-2.5 text-ink/85">Taxable in Spain as general income</td><td class="px-3.5 py-2.5 text-ink/85">Paid gross (claim NT via DTA-Individual form)</td><td class="px-3.5 py-2.5 text-ink/85">Goes in Modelo 100 base general</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Private/occupational pension</td><td class="px-3.5 py-2.5 text-ink/85">Taxable in Spain</td><td class="px-3.5 py-2.5 text-ink/85">Claim gross payment from HMRC (form Spain-Individual + Spanish residency certificate)</td><td class="px-3.5 py-2.5 text-ink/85">Same</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Government-service pension (civil service, forces, police)</td><td class="px-3.5 py-2.5 text-ink/85">NOT taxed in Spain (but counts for rate purposes — exención con progresividad)</td><td class="px-3.5 py-2.5 text-ink/85">Taxed in UK as now</td><td class="px-3.5 py-2.5 text-ink/85">Declared in Spain for progression only</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">UK rental income</td><td class="px-3.5 py-2.5 text-ink/85">Taxable in Spain</td><td class="px-3.5 py-2.5 text-ink/85">Also taxable in UK (NRL scheme) — UK keeps primary right</td><td class="px-3.5 py-2.5 text-ink/85">Spain gives credit for UK tax paid; keep the SA calculation</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">UK dividends</td><td class="px-3.5 py-2.5 text-ink/85">Taxable in Spain (savings scale 19-30%)</td><td class="px-3.5 py-2.5 text-ink/85">No UK tax for non-residents (disregarded income)</td><td class="px-3.5 py-2.5 text-ink/85">Declare gross in the base del ahorro</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">UK interest / bank accounts</td><td class="px-3.5 py-2.5 text-ink/85">Taxable in Spain</td><td class="px-3.5 py-2.5 text-ink/85">Paid gross</td><td class="px-3.5 py-2.5 text-ink/85">Base del ahorro</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">ISA income/gains</td><td class="px-3.5 py-2.5 text-ink/85">Fully taxable — wrapper ignored</td><td class="px-3.5 py-2.5 text-ink/85">None</td><td class="px-3.5 py-2.5 text-ink/85">This is why Module 1 said reset or exit</td></tr></tbody></table></div>
<p>The savings scale for 2026: 19% to €6,000 · 21% to €50,000 · 23% to €200,000 · 27% to €300,000 · 30% above. General-scale rates vary by region; Madrid and Andalucía sit lowest, Cataluña and Valencia highest.</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — Worked example — retired couple, Andalucía</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">UK state pensions €24,000 + private pension drawdown €18,000 + UK dividends €8,000 + UK bank interest €1,500. Spain: general base €42,000 → after personal allowances (2 × €5,550 + age uplifts), IRPF ≈ €7,400. Savings base €9,500 → ≈ €1,865. Total ≈ €9,265, effective ≈ 18%. Key actions that got them there: pensions paid gross from HMRC via the DTA forms (no double withholding to reclaim), and dividends moved out of the dead ISA wrapper in a pre-move reset.</div></div>' from m union all select id, 2, 'Modelo 720: the declaration you cannot skip', '<p>If on 31 December you hold foreign assets over €50,000 in any of three categories — (1) accounts, (2) securities/insurance/funds, (3) real estate — you must declare them on Modelo 720 by <strong>31 March</strong>. It is informational (no tax due with it), but non-filing penalties, even post-ECJ-softening, run €150–€300 minimum and escalate, and an unfiled 720 flags your file for inspection.</p>
<p>Practical notes:</p>
<ul>
<li>Thresholds are per <em>category</em>, valued at 31 December (accounts: also average Q4 balance).</li>
<li>Once filed, you re-file only when a category grows by >€20,000, you open/close positions, or you acquire new reportable assets.</li>
<li>Joint assets: each holder declares the full value with their ownership %.</li>
<li>UK pensions: generally <em>not</em> reportable while unvested/not in drawdown (position confirmed by DGT rulings) — but drawdown funds and SIPPs in payment are grey; this is a specific question for your asesor, not a guess.</li>
<li>Beckham participants: exempt from 720 entirely for the regime years.</li>
</ul>' from m union all select id, 3, 'Autónomo quarterlies (if self-employed)', '<p>Registered autónomo (the standard DNV freelancer path)? Your year is quarterly:</p>
<ul>
<li><strong>Modelo 130</strong> — 20% payment on account of IRPF on your quarterly profit (skipped if >70% of your invoicing had Spanish withholding — rare for foreign-client freelancers).</li>
<li><strong>Modelo 303</strong> — VAT. UK/non-EU B2B clients: outside scope. EU B2B: reverse charge (plus Modelo 349 informative). Spanish clients: 21% IVA charged and remitted.</li>
<li><strong>Social security cuota</strong> — income-banded, from ≈ €200/month at low declared yields to €590+/month at higher bands (2026 table); new autónomos get the <em>tarifa plana</em> ≈ €87/month for 12 months (extendable to 24 at low income).</li>
</ul>
<p>Deductible costs are real but formal: home-office share (30% of utilities on the m² proportion), equipment, coworking, professional insurance, the cuota itself. Keep facturas for everything — bank statements alone do not survive an inspection. A gestor runs €60–€120/month and pays for itself in avoided errors.</p>' from m union all select id, 4, 'Wealth tax and the year-one asset snapshot', '<p>Two wealth taxes exist; where you live decides whether you feel them:</p>
<ul>
<li><strong>Patrimonio</strong> — regional. Madrid and Andalucía rebate it 100% (you file but pay €0, filing only mandatory if assets >€2m or quota positive elsewhere). Valencia allowance €500k→€1m (2026 reform), Cataluña toughest. Personal allowance €700k standard + €300k main home. Full region table in the <a href="/spain/patrimonio">Patrimonio guide</a>.</li>
<li><strong>Solidaridad (ITSGF)</strong> — national, catches net wealth above €3m even in rebate regions, 1.7%–3.5% marginal. Credit given for Patrimonio actually paid.</li>
</ul>
<p>Year-one action is simple: build the 31-December asset snapshot (every account, fund, property, with documentation), because the same numbers feed Modelo 720, Patrimonio, and — one day — Sucesiones planning. An hour of spreadsheet discipline in December saves your asesor two billable hours in March.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'asesor', 'Engage a cross-border asesor fiscal for year one', 'Budget €300–€1,200 depending on 720/UK income complexity.', null from m union all select id, 1, 'dta-forms', 'File HMRC form Spain-Individual (+ Spanish residency certificate) to get UK pensions paid gross', null, null from m union all select id, 2, 'snapshot', 'Build the 31-December worldwide asset snapshot', null, null from m union all select id, 3, 'modelo-720', 'File Modelo 720 if any category >€50k', null, '31 March' from m union all select id, 4, 'modelo-100', 'File Modelo 100 (or 151 if Beckham)', null, '30 June' from m union all select id, 5, 'wealth', 'Check Patrimonio/Solidaridad position for your region', null, '30 June where due' from m union all select id, 6, 'quarterlies', 'If autónomo: calendar Modelos 130/303 quarterly', null, '20 Apr / 20 Jul / 20 Oct / 30 Jan' from m union all select id, 7, 'facturas', 'Set up factura/receipt discipline from day one (folder per quarter)', null, null from m;

-- spain/life-admin
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'life-admin');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'life-admin');
delete from public.wc_modules where country = 'spain' and slug = 'life-admin';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'life-admin', 7, 'Healthcare, schools, life admin', 'The three doors into Spanish public healthcare, when to keep private cover, how school allocation really works — and the residual admin (mobile, utilities, wills) that makes the move stick.', '90 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Healthcare: which of the three doors is yours', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Door</th><th class="px-3.5 py-2.5">Who it fits</th><th class="px-3.5 py-2.5">Cost (2026)</th><th class="px-3.5 py-2.5">Notes</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Social security contributions</td><td class="px-3.5 py-2.5 text-ink/85">Employees and autónomos</td><td class="px-3.5 py-2.5 text-ink/85">Included in contributions</td><td class="px-3.5 py-2.5 text-ink/85">Full SNS access for you + dependants from the alta</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">S1 form</td><td class="px-3.5 py-2.5 text-ink/85">UK State Pension recipients (and some exportable benefits)</td><td class="px-3.5 py-2.5 text-ink/85">Free — UK funds it</td><td class="px-3.5 py-2.5 text-ink/85">Apply to NHS Overseas Healthcare Services; register the S1 at INSS; then get your health card. Also exempts you from private-insurance requirements at renewals</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Convenio Especial</td><td class="px-3.5 py-2.5 text-ink/85">Early retirees / non-working NLV holders</td><td class="px-3.5 py-2.5 text-ink/85">€60/mo under 65 · €157/mo 65+</td><td class="px-3.5 py-2.5 text-ink/85">Requires 12 months of continuous padrón first; per person; excludes prescriptions subsidy</td></tr></tbody></table></div>
<p>Until one of those doors opens, your visa-compliant private policy (Sanitas, Adeslas, DKV, Asisa — zero-copay, no-cap versions) is doing the work. Typical 2026 premiums: ~€60–€90/month at 40, €120–€200 at 60, more past 65. Many movers keep a private policy even after entering the SNS for speed on specialists and English-speaking hospitals — downgrade to a copay version (30–50% cheaper) once it is no longer visa-critical.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Pensioners: the S1 is the single best form in this playbook</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">It hands your healthcare bill to the UK, gives you full SNS access including subsidised prescriptions (10% capped for pensioners), and satisfies renewals without private premiums. Apply before you move; it takes weeks, not days.</div></div>' from m union all select id, 1, 'Schools: how places are actually allocated', '<p>Three systems, one calendar:</p>
<ul>
<li><strong>Public (colegios públicos)</strong> — free, Spanish-medium (regional co-official languages where they exist). Places allocated on a points system: padrón catchment, siblings, renta. The main application window is <strong>February–April for September</strong>; arrive mid-year and you take what has space (the town hall education office assigns).</li>
<li><strong>Concertado</strong> — state-funded private, nominally free plus "voluntary" fees €100–€250/month. Same application windows, often religious, strong middle option.</li>
<li><strong>Private/international</strong> — €7,000–€25,000/year. British-curriculum schools cluster on the Costa del Sol, Madrid, Valencia and Barcelona (<a href="/spain/schools">full directory</a>). Entry any time subject to space; the good ones waitlist for September from January.</li>
</ul>
<p>Age placement is by calendar year of birth (not the UK September cut-off) — a child can land a school-year "behind" or "ahead" of their UK cohort; know this before it surprises you at enrolment. For under-8s arriving into public school, immersion works remarkably fast; from ~11 up, weigh the international route or a concertado with strong language support.</p>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — The padrón drives the school map</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Your catchment is fixed by your padrón address at application time. Families who rent "anywhere for now" and then apply discover their target school is out of catchment. If schools matter, choose the neighbourhood for the school first and the house second.</div></div>' from m union all select id, 2, 'The residual admin that makes it stick', '<ul>
<li><strong>Mobile + internet:</strong> port to a Spanish provider (Movistar/Vodafone/Orange or the cheap MVNOs — Digi, O2). Keep your UK number alive on a £2/month PAYG SIM for UK bank SMS codes — losing 2FA access to UK accounts from abroad is a genuine nightmare.</li>
<li><strong>Spanish will:</strong> make one covering your Spanish assets (notary, ~€60–€120, an hour). It sits alongside your UK will and, since Brussels IV, you can elect UK law to govern succession — which sidesteps Spanish forced-heirship on the estate side. It does <em>not</em> change Sucesiones tax (see the <a href="/spain/sucesiones">inheritance-tax guide</a> — beneficiaries pay, spouses are not exempt, region decides how much).</li>
<li><strong>Padrón renewals / confirmations:</strong> answer any town-hall letter within the stated window.</li>
<li><strong>UK loose ends:</strong> electoral roll (you can stay registered as an overseas voter), TV licence cancellation + refund, DVLA address rules (you cannot keep a UK-registered car in Spain beyond 6 months — matriculate it or sell it before leaving; matriculation costs typically make selling the right answer).</li>
<li><strong>Pets already here:</strong> register with a local vet, update the microchip country record, and get the Spanish pet passport at the first visit.</li>
</ul>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'healthcare-door', 'Identify your SNS door (contributions / S1 / Convenio) and start it', 'S1 applicants: request from NHS OHS before or immediately after moving.', null from m union all select id, 1, 'private-policy', 'Keep visa-compliant private cover until your SNS door opens; then downgrade or keep by choice', null, null from m union all select id, 2, 'health-card', 'Get the tarjeta sanitaria for each family member once in the system', null, null from m union all select id, 3, 'school-window', 'Apply for school places in the Feb–Apr window (or via the town hall mid-year)', 'Padrón address fixes your catchment.', null from m union all select id, 4, 'mobile', 'Move to a Spanish mobile plan; keep the UK number on cheap PAYG for 2FA', null, null from m union all select id, 5, 'will', 'Sign a Spanish will electing UK succession law (notary)', null, null from m union all select id, 6, 'car', 'Resolve the car: sell in UK or budget matriculation — 6-month limit', null, null from m union all select id, 7, 'uk-loose-ends', 'Close UK loose ends: TV licence, insurers, DVLA, overseas voter registration', null, null from m;

-- spain/years-2-to-5
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'years-2-to-5');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'spain' and slug = 'years-2-to-5');
delete from public.wc_modules where country = 'spain' and slug = 'years-2-to-5';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('spain', 'years-2-to-5', 8, 'Years 2 to 5: renewals to permanence', 'Renewal mechanics and the day-counting that protects them, the five-year switch to long-term residency, when UK ties stop mattering, and the ten-year citizenship question.', '60 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Renewals without drama', '<p>Renewal cadence depends on your card:</p>
<ul>
<li><strong>NLV:</strong> initial 1 year → renewal for 2 years → renewal for 2 more → long-term at year 5. Each renewal re-tests income (at the same IPREM multiples, using the <em>then-current</em> IPREM) and now expects evidence you actually live here: <strong>more than 183 days/year in Spain</strong>, shown through padrón continuity, school records, utility bills.</li>
<li><strong>DNV:</strong> 3-year card → 2-year renewal → long-term at 5. Renewal re-tests the remote-work relationship and income at the current SMI multiple.</li>
<li>File renewals in the window <strong>60 days before to 90 days after</strong> expiry — the after-window works but never let it happen; everything else (travel, banking) wobbles with an expired card.</li>
</ul>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — Absences are the silent renewal-killer</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">NLV holders who treat Spain as a 4-month-a-year base fail the effective-residence test at renewal — and absences over 6 months in any year (or 10 months total across 5 years) also break the continuity required for long-term residency. Keep a simple day log; boarding passes and card statements are your evidence.</div></div>' from m union all select id, 1, 'Year 5: long-term residency changes the game', '<p>At five years of continuous legal residence you qualify for <strong>larga duración</strong> — long-term residency. It matters because it decouples you from your original visa''s conditions: no more income re-testing, no more NLV work ban (you can work freely), 5-year cards renewed as formality. Apply through extranjería with your residence history, padrón continuity and absence record.</p>
<p>From here your only ongoing obligations are the universal ones: taxes (Module 6 becomes routine), padrón upkeep, and — if you were on Beckham — managing the year-7 transition onto standard IRPF, Modelo 720 and wealth tax (calendar it; year 6 is the time to realise foreign gains tax-free and restructure).</p>' from m union all select id, 2, 'The citizenship question, honestly', '<p>Spanish citizenship by residence needs <strong>10 years</strong> (UK nationals get no shortcut), the DELE A2 Spanish exam and the CCSE culture test, and — the hard part — Spain demands renunciation of your previous nationality at the oath for Brits. In practice the UK does not treat that declaration as effective loss of British citizenship, and many dual-life Britons live in exactly that ambiguity; but understand you would be making a formal renunciation declaration under Spanish law, and Spain can (rarely, but legally) act on dual-use of the renounced nationality.</p>
<p>For most buyers of this playbook, <strong>long-term residency + UK passport is the steady state</strong>: permanent rights in Spain, no renunciation question, UK citizenship intact. Citizenship is worth the trouble mainly for those with Spanish-born children anchoring here permanently (children born in Spain can claim after just 1 year of residence) or who want EU-wide free movement rights back.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — The under-appreciated year-5 move</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Even if you never want citizenship, apply for larga duración the month you qualify. It removes the income-retest risk from your life (rule changes, IPREM rises, a bad income year) and upgrades your status before any policy window can close. There is no reason to renew an NLV a third time when permanence is available.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'day-log', 'Keep a running Spain-days log with evidence (183+ days/yr; no 6-month absences)', null, null from m union all select id, 1, 'renewal-1', 'First renewal filed in the window', null, '60 days before card expiry' from m union all select id, 2, 'income-recheck', 'Re-verify income against current IPREM/SMI before each renewal', null, null from m union all select id, 3, 'larga-duracion', 'Apply for long-term residency at year 5 — do not just renew again', null, null from m union all select id, 4, 'beckham-exit', 'If on Beckham: execute the year-6 restructuring before standard rules bite in year 7', null, null from m union all select id, 5, 'citizenship', 'Make the citizenship-vs-permanent-residency decision consciously at year 8-9', null, null from m;

-- portugal/pre-move
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'pre-move');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'pre-move');
delete from public.wc_modules where country = 'portugal' and slug = 'pre-move';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'pre-move', 1, 'Pre-move UK actions', 'The UK-side sequence for a Portugal move: residency-line timing, the ISA/GIA reset, the pension lump-sum decision, property, and the two Portuguese numbers you should obtain before you even book flights.', '90 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Timing the residency line', '<p>Portuguese tax residency triggers at 183+ days in any 12-month period touching a calendar year, <em>or</em> the moment you occupy a home in Portugal with the intent it is your habitual residence — which for most movers means residency can start the day you get the keys to a long-term rental. Portugal then applies <strong>split-year treatment automatically</strong>: you are taxed as resident only from the residency start date, not the whole calendar year. That is friendlier than Spain — but it makes the exact start date documentable and important.</p>
<p>Practical sequencing: do your UK-side disposals (ISA reset, property completion, pension lump sum) strictly before the date you take up the Portuguese home. Keep the tenancy start date, flight records and utility activations consistent — the AT (Autoridade Tributária) uses them if the start date is ever questioned.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — NIF and bank account first, from the UK</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Unlike almost everything in Spain, Portugal lets you do the two foundational steps remotely before the move: get a NIF through a fiscal representative (€75–€150 online services, ~1 week) and open a Portuguese bank account remotely with that NIF (Millennium and ActivoBank both do this). Arriving with NIF + account already live cuts weeks off your setup and is required groundwork for the visa anyway.</div></div>' from m union all select id, 1, 'The UK asset reset — same logic, Portuguese numbers', '<p>Portugal, like Spain, ignores the ISA wrapper and does not rebase assets on entry. From your residency start date, disposals are taxed against original acquisition cost. Capital gains on securities are taxed at a flat <strong>28%</strong> (with an option to aggregate at marginal rates if lower — rarely is), and there is one Portuguese wrinkle to plan around: gains on securities held under 365 days are <em>forced</em> into aggregation at marginal rates (up to 53%) if your taxable income is in the top band.</p>
<p>The pre-move playbook is therefore identical in shape to Spain''s:</p>
<ol>
<li>Sell-and-repurchase ISAs and heavily-appreciated GIA positions while UK resident — reset the cost basis for free under UK CGT rules (ISA) or within your CGT allowance/planning (GIA).</li>
<li>Document everything with contract notes — they are your acquisition evidence for Portuguese CGT decades from now.</li>
<li>Ask your platforms about non-resident policies; several UK brokers restrict Portuguese-resident clients. Interactive Brokers and Swissquote are the common landing spots for movers whose platforms say no.</li>
</ol>
<p><strong>Pensions:</strong> the 25% UK tax-free lump sum is taxable in Portugal once resident (as pension income). If it is in your plan, take it while UK resident. Government-service pensions (Article 19 of the UK–Portugal DTA) stay UK-taxed; state and private pensions shift to Portuguese taxation (Module 6).</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — The lump-sum window, £300k pot</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">PCLS of £75,000 taken while UK resident: £0. Taken after Portuguese residency: taxed as pension income — for a retiree with other income it lands across the 28–45% bands, roughly €25,000–€30,000 of avoidable tax. The single most expensive "I did not know" in Portuguese moves.</div></div>' from m union all select id, 2, 'UK property decisions', '<p>Selling your UK main home? Complete while UK resident and Private Residence Relief usually zeroes the gain. Sell after Portuguese residency and Portugal taxes 50% of the gain at marginal rates (the Portuguese main-home reinvestment relief only covers homes in Portugal/EU — and only if the UK house was genuinely your main home up to sale, which post-move it no longer is).</p>
<p>Keeping and letting it? Workable and common: the UK taxes the rent first (NRL scheme — file NRL1), Portugal taxes it too at a flat 25% (Category F, with documented expenses deductible) or aggregated, and credits the UK tax. You will file in both countries every year — budget for that admin. The property also does NOT trigger any Modelo-720-style declaration, because <strong>Portugal has no foreign-asset declaration and no wealth tax</strong> — one of its quiet structural advantages over Spain.</p>' from m union all select id, 3, 'The document pack', '<p>Portugal accepts UK public documents with an FCDO apostille; translations must be certified (by a Portuguese notary, lawyer, or the consulate — Portugal has no "sworn translator" register like Spain, which paradoxically makes translations easier and cheaper).</p>
<ul>
<li>Birth and marriage certificates — apostille + certified translation</li>
<li>ACRO police certificate — apostille; under 90 days old at visa submission (order late, order two)</li>
<li>Proof of income/funds per the visa route (Module 2)</li>
<li>UK medical/vaccination records for kids'' school enrolment — plain copies usually fine</li>
</ul>
<p>2026 costs: apostille £30–£45/document; certified translations €25–€40/page; ACRO £63.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'nif', 'Obtain NIF remotely via fiscal representative', '€75–€150, ~1 week. Everything else hangs off it.', null from m union all select id, 1, 'bank', 'Open a Portuguese bank account remotely (Millennium/ActivoBank)', null, null from m union all select id, 2, 'timing', 'Fix your residency start date and sequence UK disposals before it', null, null from m union all select id, 3, 'isa-reset', 'Reset ISA/GIA cost basis while UK resident; archive contract notes', null, null from m union all select id, 4, 'pcls', 'Take the 25% pension lump sum (if planned) while UK resident', null, null from m union all select id, 5, 'property', 'Decide UK property path; if selling, complete before residency starts', null, null from m union all select id, 6, 'p85', 'File P85 (+ NRL1 if letting) with HMRC', null, 'within ~4 weeks of departure' from m union all select id, 7, 'docs', 'Apostille + certified-translate the document pack; order ACRO', null, 'ACRO <90 days at submission' from m;

-- portugal/visa
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'visa');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'visa');
delete from public.wc_modules where country = 'portugal' and slug = 'visa';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'visa', 2, 'D7 vs D8 vs the rest', 'The two routes that matter for Brits — D7 passive income and D8 digital nomad — with 2026 thresholds, the consulate file that gets approved first time, and the AIMA appointment reality on arrival.', '100 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Route selection in one table', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Route</th><th class="px-3.5 py-2.5">2026 income bar</th><th class="px-3.5 py-2.5">Income type</th><th class="px-3.5 py-2.5">Work rights</th><th class="px-3.5 py-2.5">Who it fits</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">D7</td><td class="px-3.5 py-2.5 text-ink/85">€870/mo (1× IAS-linked minimum wage basis, 2026: ~€10,440/yr) + 50% spouse + 30% per child</td><td class="px-3.5 py-2.5 text-ink/85">Passive: pensions, rent, dividends, interest</td><td class="px-3.5 py-2.5 text-ink/85">Full work rights after residence card</td><td class="px-3.5 py-2.5 text-ink/85">Retirees, FIRE, landlords</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">D8 (residency visa)</td><td class="px-3.5 py-2.5 text-ink/85">4× minimum wage = €3,480/mo (2026)</td><td class="px-3.5 py-2.5 text-ink/85">Active remote income for non-Portuguese employers/clients</td><td class="px-3.5 py-2.5 text-ink/85">Remote work; full rights after card</td><td class="px-3.5 py-2.5 text-ink/85">Employees and freelancers</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Golden Visa</td><td class="px-3.5 py-2.5 text-ink/85">€500k funds route (property route abolished)</td><td class="px-3.5 py-2.5 text-ink/85">Investment</td><td class="px-3.5 py-2.5 text-ink/85">Minimal-stay path (7 days/yr)</td><td class="px-3.5 py-2.5 text-ink/85">HNW wanting optionality, not relocation</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">D2</td><td class="px-3.5 py-2.5 text-ink/85">Business plan + means</td><td class="px-3.5 py-2.5 text-ink/85">Entrepreneurship</td><td class="px-3.5 py-2.5 text-ink/85">Run the business</td><td class="px-3.5 py-2.5 text-ink/85">Founders actually operating in PT</td></tr></tbody></table></div>
<p>Note the D7/D8 asymmetry that trips people: the D7 income bar is low (~€870/month) but must be <strong>passive</strong> — salaries do not count, and consulates increasingly reject "D7 with a remote job" files, pushing them to D8. The D8 bar is much higher (4× minimum wage) but takes your salary. There is also a savings requirement in practice for both: showing ~12 months of the threshold (€12k–€40k depending on family size) in your Portuguese bank account materially strengthens either file.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — D7 with mixed income</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Consulates accept blended passive income — pension + rent + dividends all stack. What they want is durability: 6–12 months of statements showing the income arriving, plus the underlying contracts/award letters. A one-off dividend declared last month does not read as durable.</div></div>' from m union all select id, 1, 'The application, step by step', '<ol>
<li><strong>VFS Global appointment</strong> (Portugal outsources UK visa intake to VFS in London/Manchester/Edinburgh). Book early — 3–6 week waits are normal.</li>
<li><strong>Submit the file:</strong> passport, application form, 2 photos, ACRO+apostille, proof of income (route-specific), Portuguese bank statement, proof of accommodation (12-month rental contract strongly preferred; Airbnb bookings usually rejected for D7, sometimes tolerated for D8), travel insurance covering the visa period, NIF, criminal-record consent form.</li>
<li><strong>Decision:</strong> statutory 60 days; real-world 4–10 weeks. You get a 4-month double-entry visa.</li>
<li><strong>Enter Portugal and attend the AIMA appointment</strong> — usually pre-booked by the consulate and printed on the visa letter. AIMA (successor to SEF) takes biometrics and issues your 2-year residence card (arrives by post, 2–10 weeks after).</li>
</ol>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — Guard the AIMA appointment with your life</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The AIMA appointment date on your visa letter is the single hardest thing to replace in the whole process — the rebooking backlog has run 6+ months. Book flights around it, not the other way round. If you must move it, start the moment you know.</div></div>
<p>Renewals: the first card runs 2 years, renewed for 3 (D7 renewal re-tests income; D8 re-tests the remote-work relationship). At year 5 you reach permanent residence <em>and</em> citizenship eligibility simultaneously — Portugal''s headline advantage (Module 7).</p>' from m union all select id, 2, 'Accommodation proof: the practical problem', '<p>The consulate wants a 12-month rental contract before you have even moved — the chicken-and-egg every applicant faces. The 2026 solutions, in order of preference:</p>
<ul>
<li><strong>Fly out and rent first</strong> — a scouting trip where you sign a 12-month lease (registering it with Finanças makes it airtight), then apply from the UK. Most robust; also solves schools/neighbourhood choice.</li>
<li><strong>Rent remotely</strong> through the established long-term platforms or an agent with video walkthroughs — sign, register, apply.</li>
<li><strong>Borrowed address</strong> (family/friend with an <em>atestado</em> from their junta de freguesia + letter) — accepted, weaker.</li>
<li><strong>12-month aparthotel/co-living contracts</strong> — increasingly accepted for D8, rarely for D7.</li>
</ul>
<p>Budget reality check for the lease you sign: Lisbon 1-bed €1,100–€1,600, Porto €800–€1,200, Algarve towns €700–€1,100, interior cities €500–€800. Landlords commonly ask 2 months deposit + 1–2 upfront, and a Portuguese guarantor (fiador) — offering 3–6 months upfront usually substitutes for the fiador you do not have.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'route', 'Lock D7 (passive) vs D8 (remote work) based on income type — not preference', null, null from m union all select id, 1, 'savings', 'Park ~12 months of threshold income in the Portuguese account before applying', null, null from m union all select id, 2, 'lease', 'Secure the 12-month lease (scouting trip if possible) and register it', null, null from m union all select id, 3, 'vfs', 'Book the VFS appointment', '3–6 week waits; book before the file is even finished.', null from m union all select id, 4, 'file', 'Assemble the file: ACRO, income evidence, insurance, NIF, bank statements', null, null from m union all select id, 5, 'submit', 'Submit and calendar the 60-day decision window', null, null from m union all select id, 6, 'aima', 'Fly to the AIMA appointment on the visa letter — never reschedule voluntarily', null, null from m union all select id, 7, 'card', 'Receive the 2-year residence card; scan and back up everything', null, null from m;

-- portugal/ifici
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'ifici');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'ifici');
delete from public.wc_modules where country = 'portugal' and slug = 'ifici';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'ifici', 3, 'IFICI (NHR 2.0) and the tax-regime decision', 'The old NHR is closed. Its successor IFICI gives a 20% flat rate — but only for a defined list of qualifying activities. Who genuinely fits, how to register in the January window, and what everyone else (especially pensioners) should do instead.', '75 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'What IFICI is — and is not', '<p>IFICI (Incentivo Fiscal à Investigação Científica e Inovação — "NHR 2.0") applies to new Portuguese tax residents who were non-resident for the previous 5 years and who work in a <strong>qualifying activity</strong>. Benefits, for 10 years:</p>
<ul>
<li><strong>20% flat rate</strong> on Portuguese employment/self-employment income from the qualifying activity (vs progressive rates to 48%+).</li>
<li><strong>Exemption on most foreign-source income</strong> — dividends, interest, capital gains, foreign rents (with the notable exception below).</li>
</ul>
<p>The qualifying list is the narrow part: higher-education and scientific research roles; jobs inside certified startups; roles in companies exporting 50%+ of turnover; listed high-value professions (directors, engineers, doctors, university teachers, IT specialists…) working for entities in qualifying sectors (manufacturing, IT/telecoms, R&D, audiovisual); and staff of entities certified by IAPMEI/AICEP. A remote software engineer employed by a UK tech company can often fit; a remote marketing consultant with UK clients usually cannot; a retiree never can.</p>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — Pensions are the carve-out that changed everything</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Unlike the old NHR (which taxed foreign pensions at 10% and, before 2020, 0%), IFICI gives pensions NO special treatment — foreign pension income is excluded from the exemption and taxed at standard progressive rates. Anyone who tells you they moved to Portugal for the pension tax deal is describing a regime that closed to new entrants at the end of 2023.</div></div>' from m union all select id, 1, 'The registration window', '<div class="rounded-card border border-warning/50 bg-warning/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⏰ Deadline — Register by 15 January of the year after becoming resident</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">IFICI registration is filed with the AT (or the sector body — FCT for research, IAPMEI/AICEP/Startup Portugal for their categories) by 15 January following your first year of residency. Late registration pushes the start back a year in the best case; in the worst reading it forfeits the regime. Treat it like Spain''s Modelo 149: diarise it the day your residence card arrives.</div></div>
<p>Evidence to assemble before the window: employment contract or service agreements describing the qualifying activity, employer certification of sector/export share where relevant, degree certificates for profession-based routes, and your residence documentation. Approval confirms the 20% withholding treatment for payroll (or your recibos verdes invoicing) going forward.</p>' from m union all select id, 2, 'If IFICI is not for you: the actual comparison', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Profile</th><th class="px-3.5 py-2.5">Regime reality</th><th class="px-3.5 py-2.5">Effective outcome</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Qualifying tech employee, €90k</td><td class="px-3.5 py-2.5 text-ink/85">IFICI 20% flat + foreign investment income exempt</td><td class="px-3.5 py-2.5 text-ink/85">≈ €18k tax; standard would be ≈ €31k</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Remote freelancer, non-qualifying, €60k</td><td class="px-3.5 py-2.5 text-ink/85">Standard IRS + recibos verdes simplified regime (75% coefficient)</td><td class="px-3.5 py-2.5 text-ink/85">Effective ≈ 24–28% after the simplified-regime discount; still decent</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Retired couple, £40k pensions</td><td class="px-3.5 py-2.5 text-ink/85">Standard IRS, progressive</td><td class="px-3.5 py-2.5 text-ink/85">Effective ≈ 15–20% after allowances and the pension deduction (€4,462/person)</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Under-35 worker</td><td class="px-3.5 py-2.5 text-ink/85">IRS Jovem — 100%→25% exemption ladder over 10 years (cap 55× IAS)</td><td class="px-3.5 py-2.5 text-ink/85">Often beats IFICI below ~€30k income</td></tr></tbody></table></div>
<p>The standard-IRS bands for 2026 run 13%–48% with a solidarity surcharge above €80k. Portugal''s simplified regime for the self-employed (regime simplificado) taxes only 75% of service income under €200k turnover — an automatic 25% expense allowance that makes freelancer effective rates gentler than the headline bands suggest. Run both against your mix before assuming you need IFICI at all.</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — Retired couple example — no regime needed</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">UK state + private pensions totalling €45,000/yr, taxed only in Portugal under the DTA (paid gross from HMRC after form Portugal-Individual). Joint IRS with pension deductions: ≈ €7,300, effective ≈ 16%. The absence of NHR hurts versus 2019 movers, but Portugal remains competitive — and there is no wealth tax and no 720-style declaration at all.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'five-year', 'Confirm 5-year non-residency lookback for IFICI eligibility', null, null from m union all select id, 1, 'activity-map', 'Map your role honestly against the qualifying-activity list', 'Employer sector, export share, profession codes.', null from m union all select id, 2, 'evidence', 'Collect contracts, employer certifications and degree documents', null, null from m union all select id, 3, 'register', 'File IFICI registration with AT / sector body', null, 'by 15 January after your first resident year' from m union all select id, 4, 'fallback', 'If non-qualifying: model standard IRS vs IRS Jovem (under-35s) vs simplified regime', null, null from m union all select id, 5, 'payroll', 'Confirm the 20% treatment with payroll / apply it to your invoicing once approved', null, null from m;

-- portugal/arriving
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'arriving');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'arriving');
delete from public.wc_modules where country = 'portugal' and slug = 'arriving';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'arriving', 4, 'Arriving and registering', 'NIF you already have — now the residence card, NISS, utente number, and the certificates that make you real to the Portuguese state. Plus the driving-licence exchange that Brits keep missing.', '75 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The arrival sequence', '<ol>
<li><strong>AIMA biometrics</strong> — the appointment from your visa letter. Bring: passport+visa, NIF, proof of address, proof of means, 2 photos. Card posts to your Portuguese address afterwards.</li>
<li><strong>Junta de freguesia — atestado de morada</strong> — your parish-level proof of address (the rough analogue of Spain''s padrón). Bring your lease + two neighbourhood witnesses or landlord confirmation depending on the freguesia. Needed for the utente number, driving licence and sundry admin.</li>
<li><strong>NISS (social security number)</strong> — automatic via your employer, or apply online/at Segurança Social if self-employed. Needed before your first recibo verde or payroll run.</li>
<li><strong>Utente number (SNS registration)</strong> — at your local centro de saúde with residence card (or AIMA proof), NIF and atestado. This is your NHS-number equivalent; the door to public healthcare.</li>
<li><strong>Update Finanças</strong> — flip your NIF address from "fiscal representative / UK" to your Portuguese address (this also formally severs the fiscal-rep arrangement and marks your resident status with the AT).</li>
</ol>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Get the digital keys immediately</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Activate the Chave Móvel Digital (CMD) as soon as your residence card exists — it is Portugal''s single sign-on for Finanças, Segurança Social, SNS and the junta. Portugal''s e-government is genuinely good; with CMD most of the remaining admin in this playbook becomes a web form.</div></div>' from m union all select id, 1, 'Driving licence: 90 days to notify', '<p>UK licences are exchangeable in Portugal without retest under the post-Brexit bilateral — but the rule Brits miss is the <strong>notification window: you must register/exchange your licence with IMT within 90 days of residency</strong> (counted from your residence card). Drive past that window and the licence is technically invalid in Portugal, insurance can refuse claims, and late exchange gets bureaucratically painful.</p>
<p>Process via IMT online (with CMD) or in person: licence exchange form, medical certificate for over-60s (attestation from any médico, ~€30), fee ~€30. Keep driving on the UK photocard until the Portuguese card arrives.</p>
<div class="rounded-card border border-warning/50 bg-warning/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⏰ Deadline — IMT registration within 90 days of your residence card</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Do it the same week as the utente number. It is a 20-minute online task with CMD, and the downside of missing it — retesting in Portuguese — is grim.</div></div>' from m union all select id, 2, 'Renting, registering the lease, and the bills', '<p>If you arrived on a scouting-trip lease, three tenancy notes for the long term:</p>
<ul>
<li>Leases should be <strong>registered with Finanças</strong> by the landlord (Modelo 2 do Imposto do Selo). If yours is not, the landlord is dodging tax on the rent — which becomes your problem when you need the contract as official proof of address or for IRS rent deductions (15% of rent up to €600+/yr is deductible for tenants). Ask; insist.</li>
<li>Utilities transfer with NIF + contract: EDP/Galp/Iberdrola for power+gas, municipal water, MEO/NOS/Vodafone for fibre. Direct debit from the Portuguese account.</li>
<li>Rents rose hard 2020–2025; rent-increase caps apply to existing contracts (annually indexed) — a registered contract locks in that protection.</li>
</ul>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'aima', 'Attend AIMA biometrics; receive the residence card', null, null from m union all select id, 1, 'atestado', 'Get the atestado de morada from your junta de freguesia', null, null from m union all select id, 2, 'niss', 'Obtain NISS (employer route or Segurança Social direct)', null, null from m union all select id, 3, 'utente', 'Register at the centro de saúde — utente number for each family member', null, null from m union all select id, 4, 'nif-address', 'Update NIF address at Finanças; end fiscal representation', null, null from m union all select id, 5, 'cmd', 'Activate Chave Móvel Digital for the whole household', null, null from m union all select id, 6, 'imt', 'Register/exchange UK driving licence with IMT', null, 'within 90 days of the residence card' from m union all select id, 7, 'lease-registered', 'Confirm the lease is registered with Finanças (rent deduction + proof of address)', null, null from m;

-- portugal/banking
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'banking');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'banking');
delete from public.wc_modules where country = 'portugal' and slug = 'banking';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'banking', 5, 'Portuguese banking', 'Which bank actually suits a British arrival, the MB Way/Multibanco layer that runs Portuguese life, and the Wise bridge that keeps your GBP→EUR costs near zero.', '50 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Picking the account', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Bank</th><th class="px-3.5 py-2.5">Why movers pick it</th><th class="px-3.5 py-2.5">Fees (2026)</th><th class="px-3.5 py-2.5">Remote opening?</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Millennium BCP</td><td class="px-3.5 py-2.5 text-ink/85">Largest network; polished English support; visa-friendly statements</td><td class="px-3.5 py-2.5 text-ink/85">≈ €5–7/mo (waivable with activity)</td><td class="px-3.5 py-2.5 text-ink/85">Yes — with NIF, pre-arrival</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">ActivoBank</td><td class="px-3.5 py-2.5 text-ink/85">Millennium''s no-fee digital brand; excellent app</td><td class="px-3.5 py-2.5 text-ink/85">€0</td><td class="px-3.5 py-2.5 text-ink/85">Yes (video onboarding)</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Novobanco</td><td class="px-3.5 py-2.5 text-ink/85">Strong branch coverage; expat desks in Algarve/Lisbon</td><td class="px-3.5 py-2.5 text-ink/85">≈ €5/mo tiers</td><td class="px-3.5 py-2.5 text-ink/85">Branch preferred</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Caixa Geral (CGD)</td><td class="px-3.5 py-2.5 text-ink/85">The state bank — every town has one</td><td class="px-3.5 py-2.5 text-ink/85">≈ €5/mo (waivable)</td><td class="px-3.5 py-2.5 text-ink/85">Branch</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Wise/Revolut (bridge)</td><td class="px-3.5 py-2.5 text-ink/85">GBP→EUR at mid-market ±0.4–0.6%</td><td class="px-3.5 py-2.5 text-ink/85">€0 monthly</td><td class="px-3.5 py-2.5 text-ink/85">Yes</td></tr></tbody></table></div>
<p>The architecture mirrors the Spanish module: Portuguese account for local life + Wise as the FX bridge + UK account kept open. What is different in Portugal is how much runs through <strong>Multibanco/MB Way</strong>: the national payment network handles bills (pay any utility reference at any ATM or in-app), tax payments (Finanças issues Multibanco references), and P2P (MB Way is Portugal''s Bizum — activate it with your Portuguese card + mobile number on day one). A foreign account cannot join MB Way; this is the practical reason the Portuguese account is non-negotiable.</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — Same FX math as ever</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">A UK bank international transfer at ~2.4% all-in on £3,500/month costs ≈ £1,000/year. Wise at ~0.45% ≈ £190. Set the standing monthly transfer and stop thinking about it.</div></div>' from m union all select id, 1, 'Month-one banking admin', '<ol>
<li>Upgrade the remote-opened account to full resident status (walk-in with residence card + atestado) — unlocks credit products and kills non-resident fee tiers.</li>
<li>Activate MB Way + the debit card.</li>
<li>Set utilities and rent onto direct debit / standing order.</li>
<li>Create the monthly Wise GBP→EUR standing transfer, salary/pension day + 1.</li>
<li>Store your Finanças Multibanco payment references workflow — you will use it for IMI, IUC and IRS payments (Module 6).</li>
</ol>
<p>Deposit protection: Portugal''s FGD covers €100,000 per person per bank, separate from UK FSCS. Same discipline as the Spain module: working money in Portugal, reserves placed deliberately.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'account', 'Open (or upgrade) the Portuguese account to resident status', null, null from m union all select id, 1, 'mbway', 'Activate MB Way + card on day one', null, null from m union all select id, 2, 'wise', 'Set the monthly Wise standing transfer GBP→EUR', null, null from m union all select id, 3, 'debits', 'Move rent + utilities to Portuguese direct debit', null, null from m union all select id, 4, 'multibanco', 'Learn the Multibanco reference-payment flow (taxes use it)', null, null from m union all select id, 5, 'uk-audit', 'Audit UK direct debits; notify UK bank of the Portuguese address', null, null from m;

-- portugal/year-one-tax
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'year-one-tax');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'year-one-tax');
delete from public.wc_modules where country = 'portugal' and slug = 'year-one-tax';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'year-one-tax', 6, 'Year-one IRS filing', 'The Portuguese IRS return end-to-end: the April–June window, how each UK income type lands, the recibos verdes quarterly rhythm for freelancers, and the worked examples for the standard British mixes.', '110 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The calendar and the mechanics', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">When</th><th class="px-3.5 py-2.5">What</th><th class="px-3.5 py-2.5">Who</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">1 Apr – 30 Jun</td><td class="px-3.5 py-2.5 text-ink/85">IRS return (Modelo 3) for the prior calendar year — filed at portaldasfinancas with CMD</td><td class="px-3.5 py-2.5 text-ink/85">All residents (split-year: from residency start date only)</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">By 15 Jan</td><td class="px-3.5 py-2.5 text-ink/85">IFICI registration (Module 3) — first year only</td><td class="px-3.5 py-2.5 text-ink/85">Qualifying new residents</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Quarterly</td><td class="px-3.5 py-2.5 text-ink/85">Segurança Social declarations (self-employed)</td><td class="px-3.5 py-2.5 text-ink/85">Recibos verdes workers</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Jul/Sep/Dec</td><td class="px-3.5 py-2.5 text-ink/85">IRS payments on account (self-employed above thresholds)</td><td class="px-3.5 py-2.5 text-ink/85">Some freelancers</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">31 Aug (typic.)</td><td class="px-3.5 py-2.5 text-ink/85">IMI property tax instalments begin (if you bought)</td><td class="px-3.5 py-2.5 text-ink/85">Owners</td></tr></tbody></table></div>
<p>Portugal pre-populates aggressively: employment income, Portuguese bank interest and invoiced recibos verdes appear automatically in Modelo 3. Your UK income does not — you add it via Anexo J (foreign income), which is precisely where year-one professional help earns its fee (a contabilista certificado runs €150–€400 for a standard return, €60–€120/month on retainer for freelancers).</p>' from m union all select id, 1, 'UK income in the Portuguese return', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">UK income</th><th class="px-3.5 py-2.5">Portugal</th><th class="px-3.5 py-2.5">UK after treaty</th><th class="px-3.5 py-2.5">Notes</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">State pension</td><td class="px-3.5 py-2.5 text-ink/85">Taxed (Anexo J, pension category)</td><td class="px-3.5 py-2.5 text-ink/85">Paid gross — file form Portugal-Individual with HMRC</td><td class="px-3.5 py-2.5 text-ink/85">Pension deduction €4,462/person applies</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Private/occupational pension</td><td class="px-3.5 py-2.5 text-ink/85">Taxed</td><td class="px-3.5 py-2.5 text-ink/85">Gross after DTA claim</td><td class="px-3.5 py-2.5 text-ink/85">Same</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Government-service pension</td><td class="px-3.5 py-2.5 text-ink/85">Exempt with progression</td><td class="px-3.5 py-2.5 text-ink/85">Taxed in UK</td><td class="px-3.5 py-2.5 text-ink/85">Article 19 DTA</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">UK rental income</td><td class="px-3.5 py-2.5 text-ink/85">Taxed (Cat F via Anexo J) — flat 25% option or aggregate</td><td class="px-3.5 py-2.5 text-ink/85">UK taxes first (NRL)</td><td class="px-3.5 py-2.5 text-ink/85">Credit for UK tax; keep SA calcs</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Dividends</td><td class="px-3.5 py-2.5 text-ink/85">Flat 28% (or aggregate)</td><td class="px-3.5 py-2.5 text-ink/85">No UK tax for non-residents</td><td class="px-3.5 py-2.5 text-ink/85">IFICI holders: exempt</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Interest</td><td class="px-3.5 py-2.5 text-ink/85">Flat 28%</td><td class="px-3.5 py-2.5 text-ink/85">Gross</td><td class="px-3.5 py-2.5 text-ink/85">IFICI: exempt</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Capital gains (securities)</td><td class="px-3.5 py-2.5 text-ink/85">28% flat; <365-day gains may force-aggregate for top-band taxpayers</td><td class="px-3.5 py-2.5 text-ink/85">None (except UK property)</td><td class="px-3.5 py-2.5 text-ink/85">Cost basis = original purchase — hence Module 1 reset</td></tr></tbody></table></div>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — Worked example — D8 freelancer, €72,000 turnover, non-IFICI</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Simplified regime: taxable base = 75% × €72,000 = €54,000. IRS on €54,000 (single) ≈ €14,900. Segurança Social ≈ 21.4% on 70% of relevant income ≈ €10,800/yr after the 12-month new-freelancer exemption ends. Combined effective on turnover ≈ 36% — versus ≈ 30% for the same person with IFICI approval (20% flat + SS). The IFICI delta here is ~€4,300/yr; worth one hard afternoon of eligibility work.</div></div>' from m union all select id, 2, 'Recibos verdes: the freelancer rhythm', '<ul>
<li><strong>Opening:</strong> declare início de atividade at Finanças (online, free) with your CAE activity code before your first invoice.</li>
<li><strong>Invoicing:</strong> every invoice is issued through the Finanças portal or certified software ("recibo verde" electronic receipts). UK/non-EU clients: no IVA, mention reverse-charge/localisation rules. EU B2B: reverse charge + recapitulative statement.</li>
<li><strong>IVA:</strong> exempt under Article 53 below €15,000/yr turnover (2026 threshold ~€15,000); above it, quarterly IVA returns at 23% for Portuguese-situs supplies.</li>
<li><strong>Segurança Social:</strong> first 12 months exempt (first-time self-employed). Then quarterly declarations; contribution ≈ 21.4% of 70% of the average monthly service income.</li>
<li><strong>The simplified regime</strong> taxes 75% of service turnover (50% for some activities) — no expense receipts needed up to €200k turnover. Organised accounting only wins with unusually high real costs.</li>
</ul>' from m union all select id, 3, 'If you bought property: the ownership taxes', '<p>Buying triggers a stack covered fully in the purchase annexes, but the recurring ones to calendar: <strong>IMI</strong> (0.3%–0.45% of the taxable asset value, billed May/Aug/Nov), <strong>AIMI</strong> (the additional IMI on residential holdings above €600k/person — 0.7%+ marginal), and if you ever let it, Category F filing. There is no imputed-rent tax on your own home and — worth repeating — no wealth tax and no foreign-asset declaration in Portugal at all.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'contabilista', 'Engage a contabilista certificado for year one', '€150–€400 one-off; retainer if freelancing.', null from m union all select id, 1, 'dta', 'File form Portugal-Individual + residency certificate with HMRC (pensions paid gross)', null, null from m union all select id, 2, 'atividade', 'Freelancers: file início de atividade before the first invoice', null, null from m union all select id, 3, 'ss-exemption', 'Freelancers: confirm the 12-month Segurança Social exemption is applied', null, null from m union all select id, 4, 'anexo-j', 'Compile the UK-income pack for Anexo J (P60s, SA returns, dividend/interest summaries)', null, null from m union all select id, 5, 'modelo3', 'File Modelo 3', null, '30 June' from m union all select id, 6, 'imi', 'If owner: calendar IMI instalments (May/Aug/Nov)', null, null from m;

-- portugal/years-2-to-5
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'years-2-to-5');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'portugal' and slug = 'years-2-to-5');
delete from public.wc_modules where country = 'portugal' and slug = 'years-2-to-5';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('portugal', 'years-2-to-5', 7, 'Years 2 to 5: renewals to citizenship', 'The renewal at year 2, permanence at year 5 — and Portugal''s trump card: citizenship eligibility at the same five-year mark, with dual nationality fully allowed.', '60 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Renewals and the residence you must actually maintain', '<p>The first residence card (2 years) renews for 3 more — online through AIMA''s renewal portal in most cases now, with income re-tested at then-current thresholds. Keep the same evidence discipline as Spain''s module: absences should not exceed <strong>6 consecutive months (or 8 total) per card period</strong> without justified cause, or both the renewal and the year-5 permanence can fail.</p>
<p>Meanwhile your tax life normalises: Modelo 3 each spring, IFICI holders tracking their 10-year clock, freelancers on the quarterly rhythm. Two mid-window housekeeping items worth doing: a Portuguese will (testamento — Portugal applies Brussels IV, so you can elect UK law over succession while <a href="/spain/sucesiones">unlike Spain</a> Portugal charges close family 0% stamp duty on inheritance anyway), and a fresh look at your UK pension consolidation once your Portuguese tax picture is stable (see the <a href="/qrops-vs-sipp-abroad">QROPS vs SIPP guide</a>).</p>' from m union all select id, 1, 'Year 5: permanent residence AND citizenship — simultaneously', '<p>Five years of legal residence opens two doors at once:</p>
<ul>
<li><strong>Permanent residence:</strong> unconditional status, no more income tests, renewed as formality.</li>
<li><strong>Citizenship by naturalisation:</strong> Portugal''s headline offer. Requirements: 5 years'' legal residence (counted from residence-permit issue; recent reforms count from application in some cases — check current practice at filing), <strong>A2 Portuguese</strong> (the CIPLE exam — genuinely basic conversational level; a winter of lessons), clean criminal record, and crucially <strong>no renunciation requirement</strong>: Portugal fully permits dual nationality, and the UK does too.</li>
</ul>
<p>A Portuguese passport restores everything Brexit removed — EU-wide free movement, settlement rights across 27 countries — while keeping your British citizenship intact. It extends to children (born-in-Portugal children can naturalise after 1 year; minor children naturalise with you) and, after marriage/partnership of 3 years to a Portuguese citizen, spouses.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Start the A2 Portuguese in year 3, not year 5</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The CIPLE exam is the only real gate for most applicants. Two years of one-lesson-a-week is comfortable; a panicked six months alongside naturalisation paperwork is not. Book the exam early too — CIPLE sittings fill up in Lisbon and Porto.</div></div>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — The five-year arithmetic vs Spain</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Spain: 10 years to citizenship, renunciation demanded. Portugal: 5 years, dual allowed. For a 50-year-old couple this is the difference between EU citizenship at 55 versus 60+ with a legal ambiguity attached. If EU citizenship is a goal at all, this single variable often decides the whole Iberia question — which is why we put it in the country-choice quiz.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'absence-log', 'Track absences: <6 consecutive / <8 total months per card period', null, null from m union all select id, 1, 'renewal', 'Renew the residence card (2→3 years) via AIMA', null, 'window opens 30 days pre-expiry' from m union all select id, 2, 'will', 'Sign a Portuguese will electing UK succession law', null, null from m union all select id, 3, 'portuguese', 'Start A2 Portuguese lessons by year 3; book the CIPLE exam early', null, null from m union all select id, 4, 'permanence', 'Apply for permanent residence at year 5', null, null from m union all select id, 5, 'citizenship', 'File the citizenship application at year 5 (dual nationality — no renunciation)', null, null from m;

-- gibraltar/pre-move
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'pre-move');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'pre-move');
delete from public.wc_modules where country = 'gibraltar' and slug = 'pre-move';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('gibraltar', 'pre-move', 1, 'Pre-move UK actions', 'Gibraltar-specific UK preparation: the source-of-funds dossier that decides your Cat 2 and banking outcomes, the sterling-zone simplifications, and what NOT to bother with (no apostille circus here).', '75 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'Why the Gibraltar pre-move is different', '<p>Gibraltar removes half the friction of a Spain or Portugal move — it is English-speaking, common-law, sterling, with UK-recognised qualifications and no language of bureaucracy to fight. What it adds instead is <strong>scrutiny</strong>. Everything in a Gibraltar move — Cat 2 status, HEPSS, bank accounts, even upmarket rentals — runs on anti-money-laundering-grade due diligence. Your pre-move work is therefore less about apostilles and more about building one impeccable dossier you will reuse everywhere:</p>
<ul>
<li><strong>Source-of-funds narrative:</strong> a one-page chronology of how your wealth arose (career, business sale, inheritance, property), each step evidenced — completion statements, SPA extracts, probate grants, P60/SA history.</li>
<li><strong>Source-of-wealth evidence pack:</strong> last 3 years of tax returns, 6–12 months of statements for each major account, investment portfolio valuations, property valuations.</li>
<li><strong>Identity set:</strong> certified passport copies (UK solicitor/notary certification is accepted — no apostille needed for most Gibraltar purposes), recent utility bills, and a clean ACRO certificate.</li>
</ul>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Build the dossier once, use it five times</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Finance Centre (Cat 2), the bank, the landlord''s agent, the insurance broker and — if you buy — the conveyancer will each run KYC. A pre-built, indexed PDF dossier turns five interrogations into five formalities. HNW service providers in Gibraltar privately admit the quality of this pack is the biggest single predictor of processing speed.</div></div>' from m union all select id, 1, 'UK tax exit: the SRT matters more here', '<p>Gibraltar has <strong>no double tax treaty network</strong> in the usual sense — but it has one crucial instrument: the <strong>UK–Gibraltar DTA (2019)</strong>. It allocates taxing rights between the UK and Gibraltar and contains the tie-breaker that decides close cases. Because Gibraltar is 20 minutes from Marbella and many movers keep deep UK ties, the <a href="/uk-statutory-residence-test">UK Statutory Residence Test</a> is the battleground: HMRC pursues "Gibraltar residents" who in substance never left Britain''s orbit.</p>
<p>Non-negotiables for a clean exit:</p>
<ul>
<li>Run the SRT properly for your departure year and claim split-year treatment on the SA109.</li>
<li>Day-count religiously from day one — Gibraltar residency itself has day requirements (Module 2) and the UK side has SRT bands; you are counting for two systems at once.</li>
<li>Understand what stays UK-taxed regardless: UK rental income, UK government-service pensions, and UK-situs assets for IHT (see below).</li>
</ul>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — IHT does not move with you</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">UK inheritance tax follows long-term residence (the post-2025 residence-based regime): leaving for Gibraltar starts a clock, but you generally remain in UK IHT scope for years after departure (up to 10 depending on your history). Gibraltar itself has NO inheritance tax — the mismatch is a planning window, not an instant escape. Estate planning belongs in year one, not year five.</div></div>' from m union all select id, 2, 'Sterling simplifications — and the one currency decision', '<p>No currency conversion on your wealth, no Modelo 720 analogue, no wealth tax, no CGT, no VAT. The financial move itself is close to trivial: your UK accounts keep working, Gibraltar banks hold GBP natively, and the Gibraltar pound is pegged 1:1.</p>
<p>The one real currency decision: if your life will straddle the frontier (live or spend heavily in Spain — most do), you need a EUR layer. Set up Wise/Revolut for EUR spending before you move, and if you will rent in Spain while working in Gibraltar (Module 4), plan which side your salary lands and how it crosses.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'dossier', 'Build the indexed source-of-funds/wealth dossier (one PDF)', '3 yrs tax returns, statements, valuations, wealth chronology.', null from m union all select id, 1, 'acro', 'Order ACRO certificate (certified copy, no apostille needed)', null, null from m union all select id, 2, 'srt', 'Run the SRT for your departure year; plan the split-year claim', null, null from m union all select id, 3, 'p85', 'File P85 (+ NRL1 if letting UK property)', null, null from m union all select id, 4, 'iht', 'Map your UK IHT exposure clock and brief an estate planner', null, null from m union all select id, 5, 'eur-layer', 'Set up the EUR layer (Wise/Revolut) for the Spanish side of life', null, null from m;

-- gibraltar/cat-2
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'cat-2');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'cat-2');
delete from public.wc_modules where country = 'gibraltar' and slug = 'cat-2';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('gibraltar', 'cat-2', 2, 'Category 2 status', 'The HNW residency route end-to-end: the £2m net-worth test, approved accommodation, the Finance Centre application, the £37,000–£42,380 tax band it buys you, and the annual obligations that keep it.', '120 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'What Cat 2 actually buys', '<p>Category 2 status caps your Gibraltar income tax by assessing only the first <strong>£118,000</strong> of worldwide income under the Gross Income Based system. The result: a minimum annual tax of <strong>£37,000</strong> and a maximum of <strong>£42,380</strong> (2025/26 rates — Gibraltar''s tax year runs 1 July to 30 June). Whether you earn £200,000 or £20 million, the Gibraltar bill sits in that band.</p>
<p>Add what Gibraltar does not have — no CGT, no wealth tax, no inheritance tax, no VAT, no tax on savings interest or (for Cat 2 individuals) dividends from quoted companies — and the effective proposition for a £500k+/year individual is an all-in rate under 10%. That is the product. The price of admission:</p>
<ul>
<li><strong>Net worth above £2 million</strong>, evidenced to the Finance Centre Director''s satisfaction.</li>
<li><strong>Approved residential accommodation</strong> in Gibraltar — owned or rented — of a standard befitting the status, available to you year-round and not sublet.</li>
<li><strong>No prior Gibraltar residence or employment</strong>: not resident in the previous 5 years, and no gainful occupation in Gibraltar (limited exceptions — directorships of certain group entities can be permitted with consent).</li>
<li>Character requirements: references, clean record, the dossier from Module 1.</li>
</ul>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — The arithmetic vs staying in the UK</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">UK additional-rate taxpayer on £600,000: income tax ≈ £258,000. Cat 2 in Gibraltar: £42,380 (max), plus no CGT on the portfolio and no further tax on investment income. Annual delta ≈ £215,000+. Against that: the cost of the accommodation requirement (£30k–£60k/yr rent for a qualifying flat) and the real obligation to make Gibraltar your genuine residence. For income above ~£180k the numbers dominate almost any Spanish or Portuguese structure — see the Spain-vs-Gibraltar comparison for the crossover analysis.</div></div>' from m union all select id, 1, 'The application, step by step', '<ol>
<li><strong>Engage a local sponsor.</strong> Applications go through a Gibraltar professional (law firm or accountancy — mandatory in practice). Fees £3,000–£7,500 for the application package.</li>
<li><strong>Secure the accommodation first.</strong> The Finance Centre wants the address in the application. Qualifying stock clusters in Ocean Village, Kings Wharf, Midtown, EuroCity, the South District. Rentals £2,500–£5,000+/month for a qualifying 2-bed; purchases £450k–£1.5m+. Your sponsor will confirm a specific unit "qualifies" before you commit.</li>
<li><strong>File the application:</strong> form, £1,050 non-refundable fee (2026), the dossier (net-worth evidence, references — typically one banker''s and one professional reference — certified IDs, CV, accommodation evidence, private medical insurance covering Gibraltar).</li>
<li><strong>Finance Centre review:</strong> 4–10 weeks typically. Interviews are rare but possible.</li>
<li><strong>Certificate issued.</strong> Register with the Income Tax Office, obtain your civilian registration card, import your effects.</li>
</ol>
<p>The certificate is indefinite while conditions hold — but it is <em>reviewed</em>: the accommodation must stay, the ITO expects the annual return and the tax paid, and a Cat 2 who visibly lives in Marbella full-time invites precisely the scrutiny the status is designed to avoid.</p>
<div class="rounded-card border border-gibraltar/40 bg-gibraltar/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">⚠️ Costly mistake — Cat 2 is a residence status, not a brass plate</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The Finance Centre and the ITO both expect genuine residence — and Spain actively hunts sham Gibraltar residents under the 2021 Spain–Gibraltar tax treaty: Spanish tax residency is asserted over individuals with Spanish spouses/homes/183+ Spanish days, with a presumption that is hard to rebut. If your life is actually in Sotogrande, Spain will tax you like it. The playbook position: live on the Rock enough that the question never gets interesting — and keep the day log to prove it.</div></div>' from m union all select id, 2, 'Annual obligations and the family position', '<ul>
<li><strong>Tax return</strong> to the ITO each year (Gibraltar tax year 1 July–30 June; return due 30 November). Your sponsor/accountant files it; the tax lands in the £37,000–£42,380 band, payable in instalments.</li>
<li><strong>Keep the accommodation</strong> — a lapsed lease unravels the status.</li>
<li><strong>Insurance</strong> — maintain private medical cover (Module 5 of the health section covers Gibraltar''s GHA entitlements; Cat 2 holders are expected to carry private cover).</li>
<li><strong>Spouse and children:</strong> a spouse can be included within the holder''s status (joint assessment within the same cap); children can attend Gibraltar''s schools. One Cat 2 certificate covers the household''s Gibraltar tax life.</li>
</ul>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'sponsor', 'Engage a Gibraltar law/accountancy firm as sponsor', '£3,000–£7,500 application package.', null from m union all select id, 1, 'accommodation', 'Secure qualifying accommodation (confirm the specific unit qualifies before signing)', null, null from m union all select id, 2, 'networth', 'Evidence net worth >£2m in the dossier format', null, null from m union all select id, 3, 'references', 'Obtain banker''s + professional references', null, null from m union all select id, 4, 'insurance', 'Put private medical insurance covering Gibraltar in place', null, null from m union all select id, 5, 'file', 'File the Cat 2 application (£1,050 fee) and track the 4–10 week review', null, null from m union all select id, 6, 'register', 'On approval: register with the Income Tax Office; get the civilian registration card', null, null from m union all select id, 7, 'annual', 'Diarise the annual return', null, '30 November each year' from m union all select id, 8, 'day-log', 'Start the two-sided day log (Gibraltar days AND Spain days) from day one', null, null from m;

-- gibraltar/hepss
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'hepss');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'hepss');
delete from public.wc_modules where country = 'gibraltar' and slug = 'hepss';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('gibraltar', 'hepss', 3, 'HEPSS for specialists', 'The employment-based special status: £160,000+ qualifying salary, tax capped on the first £160,000 (≈ £39,940/yr), and how the employer-driven process actually runs.', '60 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'What HEPSS is and who fits', '<p>HEPSS — High Executive Possessing Specialist Skills — is Cat 2''s employment-market sibling. Where Cat 2 requires wealth and forbids local work, HEPSS requires a senior job and caps the tax on it: you are taxed only on the first <strong>£160,000</strong> of employment income under the GIBS scale, giving a fixed liability of about <strong>£39,940/year</strong> regardless of how far above £160k your package goes.</p>
<p>Qualifying conditions:</p>
<ul>
<li>Salary <strong>above £160,000</strong> from a Gibraltar employer;</li>
<li>Skills <strong>not readily available in Gibraltar</strong> and of exceptional economic value — the classic cases are gaming/e-gaming executives, insurance and fund-management leadership, fintech/DLT founders and senior engineers;</li>
<li><strong>Approved residential accommodation</strong> (same standard as Cat 2 in kind, if not price bracket);</li>
<li>Not resident in Gibraltar in the previous 3 years.</li>
</ul>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — HEPSS vs UK PAYE on £350,000</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">UK: income tax ≈ £145,000 + employee NI. HEPSS: ≈ £39,940 flat. Annual saving ≈ £110,000. The employer also wins — Gibraltar employer social insurance is capped at trivial levels (≈ £50/week max) versus 15% UK employer NI ≈ £52,000. HEPSS is why Gibraltar''s gaming and insurance sectors can outbid London for senior talent on net pay while paying less gross.</div></div>' from m union all select id, 1, 'The employer-driven process', '<p>HEPSS is applied for by the <strong>employer</strong> to the Finance Centre — you supply, they file:</p>
<ol>
<li>Employer confirms the role qualifies (their HR/advisers know the Finance Centre''s expectations; most large Gibraltar employers have filed dozens).</li>
<li>You provide: CV evidencing the specialist skills, certified passport, references, accommodation evidence, the contract showing £160k+.</li>
<li>Finance Centre issues the HEPSS certificate — typically faster than Cat 2 (2–6 weeks) because the employer stands behind the file.</li>
<li>Payroll then withholds under the capped basis from day one.</li>
</ol>
<p>Losing the job = losing the status (you revert to ordinary taxpayer rates, or leave, or requalify with a new qualifying role). Changing employer requires a fresh certificate — build that into any move negotiation. And the same residence reality as Cat 2 applies: HEPSS holders commuting from Spanish villas are exactly who the 2021 Spain treaty targets; if you live Spain-side, you are a frontier worker taxed in Spain on worldwide income (Module 4), and HEPSS bought you nothing. Live on the Rock.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'offer', 'Confirm the offer exceeds £160,000 and the employer will sponsor HEPSS', null, null from m union all select id, 1, 'cv-evidence', 'Assemble CV + evidence of specialist skills for the file', null, null from m union all select id, 2, 'accommodation', 'Secure approved accommodation before the application', null, null from m union all select id, 3, 'certificate', 'Employer files; certificate in hand before payroll day one', null, null from m union all select id, 4, 'residence', 'Establish genuine Gibraltar residence — do not commute from Spain', null, null from m union all select id, 5, 'change-plan', 'If changing employer later: new HEPSS certificate negotiated into the move', null, null from m;

-- gibraltar/frontier
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'frontier');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'frontier');
delete from public.wc_modules where country = 'gibraltar' and slug = 'frontier';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('gibraltar', 'frontier', 4, 'Frontier and the Spain question', 'The 2026 EU–Gibraltar treaty rewires the border: what changes at the frontier, the frontier-worker tax mechanics that catch people, and the honest decision framework for living Spain-side vs Rock-side.', '100 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The 2026 treaty: what actually changes', '<p>The EU–UK agreement on Gibraltar — politically settled in June 2025, operational from <strong>15 July 2026</strong> — ends eight years of border limbo. The practical architecture:</p>
<ul>
<li><strong>Fluid land frontier:</strong> systematic passport stamping at the fence ends. Gibraltar joins the Schengen operational area for movement purposes, with entry checks performed at Gibraltar''s port and airport (dual controls with Spanish/EU officers) instead of at the land border.</li>
<li><strong>For residents:</strong> Gibraltar residency cards function for frontier crossing without the 90/180 Schengen day-counting that tormented UK-passport residents since Brexit.</li>
<li><strong>For workers:</strong> the ~15,000 daily cross-border workers keep protected status; commuting both directions becomes as frictionless as it was pre-2016.</li>
<li><strong>Goods:</strong> Gibraltar aligns with EU customs arrangements for goods — import duty structures change (cars, tobacco pricing) and some retail price gaps with Spain narrow.</li>
</ul>
<p>What does <em>not</em> change: Gibraltar''s tax system (the caps, the absence of CGT/IHT/VAT survive — the treaty is about movement and goods, not direct tax), UK sovereignty, and the 2021 Spain–Gibraltar tax treaty''s residence rules — which become <em>more</em> important as the border gets easier, because easy crossing makes Spain-side living more tempting and Spanish tax residency easier to stumble into.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — The treaty makes the Rock MORE valuable, not less</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">The historic discount on Gibraltar life — queue risk at the fence, stranded-asset anxiety — is going. Same tax caps, none of the friction, full Schengen access from your doorstep. Expect qualifying-accommodation prices and rents to reflect this within a couple of years; movers deciding in 2026 are buying before the repricing completes.</div></div>' from m union all select id, 1, 'Frontier-worker mechanics: who taxes what', '<p>Live in Spain, work in Gibraltar — the classic setup for thousands. The 2021 tax treaty draws the lines:</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Situation</th><th class="px-3.5 py-2.5">Where taxed</th><th class="px-3.5 py-2.5">Mechanics</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Spanish-resident frontier worker, Gibraltar salary</td><td class="px-3.5 py-2.5 text-ink/85">Spain taxes worldwide income including the salary; Gibraltar taxes the employment income at source</td><td class="px-3.5 py-2.5 text-ink/85">Spain credits Gibraltar tax paid — you file Modelo 100 in Spain every year, declaring the Gibraltar salary</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Gibraltar-resident (Cat 2/HEPSS/ordinary), no Spanish ties</td><td class="px-3.5 py-2.5 text-ink/85">Gibraltar only</td><td class="px-3.5 py-2.5 text-ink/85">The clean case — keep it clean with the day log</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Registered Gibraltarian/resident pre-2021 with Spanish home</td><td class="px-3.5 py-2.5 text-ink/85">Grandfathered rules</td><td class="px-3.5 py-2.5 text-ink/85">Specialist advice; do not self-assess</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Spanish spouse + Spanish home + Gibraltar job</td><td class="px-3.5 py-2.5 text-ink/85">Spain will assert residency</td><td class="px-3.5 py-2.5 text-ink/85">The treaty presumptions bite; plan as a Spanish resident</td></tr></tbody></table></div>
<p>Social security is separate from tax: frontier workers pay Gibraltar social insurance on Gibraltar employment and access both systems under the coordination rules (healthcare via the frontier-worker provisions — GHA for work-related, SNS via the S1-equivalent route Spain-side). Pensions accrued in Gibraltar export to Spain on retirement.</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — The frontier arithmetic on £80,000</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Gibraltar-resident: GIBS tax ≈ £19,500, no Spanish filing. Spain-resident frontier worker: Gibraltar deducts ≈ £19,500 at source, Spain computes IRPF on the same income ≈ €26,500, credits the Gibraltar tax, and collects the difference ≈ €4,000–€6,000 — plus your worldwide investment income is now in Spanish scope, plus Modelo 720, plus (region-dependent) wealth tax. Cheaper Spanish rent rarely survives that stack. Run both columns before choosing the Sotogrande villa.</div></div>' from m union all select id, 2, 'The honest live-where decision', '<p>The framework we walk buyers through:</p>
<ul>
<li><strong>Income above ~£120k or meaningful investment wealth →</strong> live Rock-side. The Gibraltar caps and zero-CGT/IHT position only work for Gibraltar residents; Spanish residence forfeits the whole structure.</li>
<li><strong>Salary under ~£60k, family already Spain-rooted →</strong> Spain-side frontier working is legitimate and common; you pay Spanish rates net of credit and accept Spanish worldwide taxation. La Línea rents at a third of Gibraltar''s are the honest compensation.</li>
<li><strong>The in-between band →</strong> this is where people get it wrong in both directions. Model it properly (both tax columns + rent + schools) rather than defaulting to the villa.</li>
</ul>
<p>Whatever you choose, choose it <em>visibly</em>: lease, utilities, day log, gym membership, GP registration — build the evidence trail of the residence you claim. Both tax authorities read the same facts.</p>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'decide', 'Run the live-where model: both tax columns + rent + schools', 'Rock-side for high income/wealth; Spain-side only with eyes open.', null from m union all select id, 1, 'treaty-date', 'Calendar 15 July 2026 — treaty operational date changes crossing logistics', null, null from m union all select id, 2, 'day-log', 'Maintain the two-sided day log with evidence', null, null from m union all select id, 3, 'spain-filing', 'If Spain-side: register with AEAT and file Modelo 100 declaring Gibraltar income', null, null from m union all select id, 4, 'ss-coordination', 'Confirm social insurance registration and healthcare route for your setup', null, null from m union all select id, 5, 'evidence', 'Build the residence evidence trail (lease, utilities, registrations) for the side you claim', null, null from m;

-- gibraltar/banking
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'banking');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'banking');
delete from public.wc_modules where country = 'gibraltar' and slug = 'banking';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('gibraltar', 'banking', 5, 'Gibraltar banking', 'A small, compliance-heavy banking market: who actually opens accounts for new arrivals, what the due diligence wants, and the GBP/EUR architecture for a frontier life.', '60 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The market, honestly', '<p>Gibraltar banking is small and selective — a handful of institutions, all running full KYC on every newcomer. The realistic options for a new arrival:</p>
<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">Institution</th><th class="px-3.5 py-2.5">Who it serves</th><th class="px-3.5 py-2.5">Notes</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Gibraltar International Bank (GIB)</td><td class="px-3.5 py-2.5 text-ink/85">The default local bank — residents, Cat 2, businesses</td><td class="px-3.5 py-2.5 text-ink/85">Current/savings in GBP + EUR; expects the full dossier; opening 2–6 weeks</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">NatWest International</td><td class="px-3.5 py-2.5 text-ink/85">Established retail presence</td><td class="px-3.5 py-2.5 text-ink/85">Familiar UK-style banking; residence evidence required</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Jyske Bank (private)</td><td class="px-3.5 py-2.5 text-ink/85">HNW / Cat 2 private banking</td><td class="px-3.5 py-2.5 text-ink/85">Investment-led relationships, £250k+ typically</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Turicum, IDT, other private banks</td><td class="px-3.5 py-2.5 text-ink/85">HNW private clients</td><td class="px-3.5 py-2.5 text-ink/85">Bespoke; sponsor-introduced</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">UK accounts you keep</td><td class="px-3.5 py-2.5 text-ink/85">Everyday sterling</td><td class="px-3.5 py-2.5 text-ink/85">Most movers keep UK banking running — it works fine from Gibraltar</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Wise/Revolut</td><td class="px-3.5 py-2.5 text-ink/85">EUR layer for Spain-side life</td><td class="px-3.5 py-2.5 text-ink/85">Essential for frontier spending</td></tr></tbody></table></div>
<p>Practical truth: because Gibraltar is sterling and your UK banks keep working, the local account is less urgent than in Spain/Portugal — but you need one for salary (HEPSS), rent, and utilities, and Cat 2 applicants look stronger with a local banking relationship. Start the GIB application the week you sign accommodation; the dossier from Module 1 is exactly what they ask for.</p>
<div class="rounded-card border border-sea/40 bg-sea/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">✓ Buyer tip — Expect the questions, pre-empt them</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">Gibraltar banks decline vague files quickly — it is a de-risking jurisdiction. Cover letter stating who you are, why Gibraltar, source of funds, expected account activity (amounts, directions, counterparties) turns a 6-week maybe into a 2-week yes.</div></div>' from m union all select id, 1, 'The GBP/EUR architecture', '<p>Life on the Rock runs in pounds; half of most residents'' spending (Spanish supermarkets, restaurants, fuel, weekend trips) runs in euros. The clean setup:</p>
<ul>
<li>Salary/income → Gibraltar or UK GBP account.</li>
<li>Wise/Revolut multi-currency for EUR: hold a EUR balance, pay Spanish merchants by card at mid-market rates, Bizum-substitute via card for most needs (you cannot get actual Bizum without a Spanish account).</li>
<li>If you keep a Spanish property or heavy Spain-side commitments: one Spanish account (see the Spain playbook''s banking module) fed monthly from Wise.</li>
<li>Savings/investments: with no Gibraltar CGT or savings tax, the location driver is protection and platform quality, not tax — Gibraltar deposits are covered by the GDGB to €100,000-equivalent; UK FSCS £85k applies to UK accounts.</li>
</ul>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'gib-account', 'Apply to GIB (or NatWest Intl) with the dossier + activity cover letter', null, null from m union all select id, 1, 'eur-layer', 'Set up the Wise/Revolut EUR layer for Spain-side spending', null, null from m union all select id, 2, 'salary', 'Route salary/pension to the GBP account; set rent + utilities', null, null from m union all select id, 3, 'spanish-account', 'Open a Spanish account only if you have real Spain-side commitments', null, null from m union all select id, 4, 'protection', 'Check deposit-protection spread across GDGB / FSCS', null, null from m;

-- gibraltar/years-2-to-5
delete from public.wc_module_sections where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'years-2-to-5');
delete from public.wc_module_checklist where module_id in (select id from public.wc_modules where country = 'gibraltar' and slug = 'years-2-to-5');
delete from public.wc_modules where country = 'gibraltar' and slug = 'years-2-to-5';
with m as (insert into public.wc_modules (country, slug, module_number, title, summary, duration, published) values ('gibraltar', 'years-2-to-5', 6, 'Years 2 to 5: compliance and consolidation', 'The annual rhythm that keeps Cat 2/HEPSS alive, the UK tails (IHT clock, SRT drift) to keep managing, permanent residence — and the estate-planning window Gibraltar uniquely opens.', '50 min', true) returning id), s as (insert into public.wc_module_sections (module_id, position, title, body_html) select id, 0, 'The annual compliance rhythm', '<div class="not-prose my-5 overflow-x-auto rounded-card border border-border"><table class="w-full text-left text-[14px]"><thead class="bg-surface text-[11.5px] font-semibold uppercase tracking-[0.06em] text-muted"><tr><th class="px-3.5 py-2.5">When</th><th class="px-3.5 py-2.5">What</th><th class="px-3.5 py-2.5">Who</th></tr></thead><tbody class="divide-y divide-border bg-white"><tr><td class="px-3.5 py-2.5 font-semibold text-ink">30 November</td><td class="px-3.5 py-2.5 text-ink/85">Gibraltar tax return (year ended 30 June)</td><td class="px-3.5 py-2.5 text-ink/85">Everyone — Cat 2, HEPSS, ordinary</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Ongoing</td><td class="px-3.5 py-2.5 text-ink/85">Accommodation condition maintained; insurance renewed</td><td class="px-3.5 py-2.5 text-ink/85">Cat 2 / HEPSS</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Continuous</td><td class="px-3.5 py-2.5 text-ink/85">Two-sided day log (Gibraltar / Spain / UK)</td><td class="px-3.5 py-2.5 text-ink/85">Everyone with cross-border life</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Jan (UK)</td><td class="px-3.5 py-2.5 text-ink/85">UK SA for any continuing UK-source income (rent, gov pensions)</td><td class="px-3.5 py-2.5 text-ink/85">Those with UK tails</td></tr><tr><td class="px-3.5 py-2.5 font-semibold text-ink">Annually</td><td class="px-3.5 py-2.5 text-ink/85">Civilian registration card / residence permits current</td><td class="px-3.5 py-2.5 text-ink/85">All residents</td></tr></tbody></table></div>
<p>Cat 2 and HEPSS both survive on quiet consistency: tax paid, accommodation held, residence real. The failure mode is drift — more Spain days each year, the lease quietly downgraded, until a review or a Spanish information request (the 2021 treaty has active exchange-of-information) forces the question. The day log answers it before it is asked.</p>' from m union all select id, 1, 'UK tails: the clocks still running', '<ul>
<li><strong>IHT residence clock:</strong> under the residence-based IHT regime, your worldwide estate typically stays in UK IHT scope for up to 10 years after departure (based on your prior UK residence history). Gibraltar has no estate taxes at all — so each year the clock runs down, the planning window widens. Year 2–3 is when to do the serious estate work: wills on both sides, asset-situs review, trust/insurance structures where appropriate, with advisers who know both systems.</li>
<li><strong>SRT drift:</strong> UK days have a habit of creeping (family, board seats, cricket season). Re-run the <a href="/uk-statutory-residence-test">sufficient-ties test</a> annually — your tie count changes as you shed UK accommodation and family links, and your safe day allowance moves with it.</li>
<li><strong>UK-source income</strong> (rent, government pensions) stays on UK SA indefinitely — keep the January habit.</li>
</ul>' from m union all select id, 2, 'Permanence and the long game', '<p>Civilian status consolidates with time: permanent residence certificates become available after 10 years (5 for some categories), and British citizens in Gibraltar are — of course — already British; there is no new citizenship to seek, no language exam, no renunciation question. Gibraltar''s long game is simpler than Iberia''s: keep the conditions, keep the residence real, and the structure compounds quietly — no CGT on decades of portfolio growth, no IHT once the UK clock expires, income tax capped for as long as Cat 2/HEPSS holds.</p>
<div class="rounded-card border border-warm/40 bg-warm/5 p-4 my-5 not-prose"><div class="text-[12px] font-semibold uppercase tracking-[0.08em] text-ink/60">£ Worked numbers — The 10-year compounding view</div><div class="mt-1.5 text-[15px] leading-relaxed text-ink/90">A Cat 2 household with £3m invested at 6% real: in Spain (post-Beckham) the growth would face 19–30% CGT on realisation plus wealth tax drag in most regions; in Gibraltar, £0 on both. Over a decade that difference alone is £250,000–£450,000 — before comparing income-tax bands. The Rock''s pitch is not the year-one saving; it is the compounding.</div></div>' from m returning module_id) insert into public.wc_module_checklist (module_id, position, item_id, label, detail, deadline) select id, 0, 'return', 'File the Gibraltar return every year', null, '30 November' from m union all select id, 1, 'conditions', 'Annual self-audit: accommodation, insurance, day log, registrations', null, null from m union all select id, 2, 'estate', 'Do the estate-planning work in years 2–3 while the UK IHT clock runs down', null, null from m union all select id, 3, 'srt-annual', 'Re-run the UK SRT tie count annually', null, null from m union all select id, 4, 'uk-sa', 'Keep filing UK SA for UK-source tails', null, '31 January' from m union all select id, 5, 'permanence', 'Apply for permanent residence when the qualifying period completes', null, null from m;

